use anyhow::{Context, Result};
use std::collections::BTreeMap;
use tree_sitter::{Node, Parser};

use crate::cfg::{CfgNodeKind, ControlFlowGraph, FunctionParam, ResourceKind};
use crate::extractors::ir::{
    build_declaration_props as ir_build_declaration_props,
    build_entry_props as ir_build_entry_props,
    build_expression_statement_props as ir_build_expression_statement_props,
    build_return_props as ir_build_return_props, ir_as_simple_ident, ir_call_callee_args,
};
use crate::extractors::{ExtractionArtifacts, LanguageExtractor};
use crate::serialization::{PolyglotProofDeclaration, PolyglotStructuredDeclaration};
use crate::source_map::SourceSpan;

pub struct TypeScriptExtractor;

impl LanguageExtractor for TypeScriptExtractor {
    fn language_id(&self) -> &str {
        "typescript"
    }

    fn file_extensions(&self) -> &[&str] {
        &[".ts", ".tsx", ".js", ".jsx", ".mjs", ".cjs"]
    }

    fn extract(&self, source: &str, file_path: &str) -> Result<Vec<ControlFlowGraph>> {
        Ok(self.extract_with_artifacts(source, file_path)?.cfgs)
    }

    fn extract_with_artifacts(&self, source: &str, file_path: &str) -> Result<ExtractionArtifacts> {
        let mut parser = Parser::new();
        let is_tsx = file_path.ends_with(".tsx") || file_path.ends_with(".jsx");
        let language = if is_tsx {
            tree_sitter_typescript::LANGUAGE_TSX.into()
        } else {
            tree_sitter_typescript::LANGUAGE_TYPESCRIPT.into()
        };
        parser
            .set_language(&language)
            .context("failed to set TypeScript grammar")?;

        let tree = parser
            .parse(source, None)
            .context("failed to parse TypeScript source")?;

        let root = tree.root_node();
        let mut cfgs = Vec::new();

        // Collect module-level binding declarations once, then attach the
        // serialized JSON to every Entry node we emit so gnexec can run them
        // before the function body in fresh module scope.
        let module_preamble = collect_module_preamble(&root, source);

        extract_functions_recursive(
            &root,
            source,
            file_path,
            &mut cfgs,
            module_preamble.as_deref(),
        )?;

        // Synthesize a `__module_main__` topology for files whose top level is
        // an imperative script (bare expression statements, top-level loops,
        // top-level `await main()`, etc.) rather than only declarations. The
        // function extractor above emits a topology PER function declaration but
        // nothing for top-level executable statements, so a bare script like
        // `console.log("hi")` previously produced zero topologies and gnexec
        // declined with "no topologies emitted". This entry treats the whole
        // program body as a function body: gnexec's walker already evaluates the
        // resulting Statement/Branch nodes (console.log, fetch, etc.) — we just
        // give it an Entry to start from. Pure-declaration / pure-function
        // modules (no executable top-level statement) skip this so existing
        // single-topology and analysis behavior is unchanged.
        if let Some(main_cfg) =
            extract_module_main_cfg(&root, source, file_path, module_preamble.as_deref())?
        {
            cfgs.push(main_cfg);
        }

        let (structured_declarations, proof_declarations) =
            extract_jsx_declarations(&root, source, file_path);

        Ok(ExtractionArtifacts {
            cfgs,
            structured_declarations,
            proof_declarations,
        })
    }
}

fn extract_functions_recursive(
    node: &Node,
    source: &str,
    file_path: &str,
    cfgs: &mut Vec<ControlFlowGraph>,
    module_preamble: Option<&str>,
) -> Result<()> {
    match node.kind() {
        // `class_declaration` is `class Foo { ... }`. `class` is a class
        // EXPRESSION — `var Foo = class { ... }` — which is exactly the form
        // esbuild emits when it bundles ESM classes (it renames the binding and
        // lowers the declaration to `var X = class {}`). Both lower to the same
        // `<Class>.method` / `<Class>.constructor` topologies; the only
        // difference is where the class NAME comes from (the `name` field for a
        // declaration, the enclosing `variable_declarator` for an expression).
        // Without the `class` arm the bundled aether engine bailed the walker
        // with "unhandled AST node 'class'", blocking headless inference.
        "class_declaration" | "class" => {
            let class_name = node
                .child_by_field_name("name")
                .map(|n| node_text(n, source))
                .or_else(|| {
                    // Class expression: take the name from `var NAME = class {}`
                    // (or an assignment `NAME = class {}`).
                    node.parent().and_then(|p| match p.kind() {
                        "variable_declarator" | "assignment_expression" => p
                            .child_by_field_name("name")
                            .or_else(|| p.child_by_field_name("left"))
                            .map(|n| node_text(n, source)),
                        _ => None,
                    })
                })
                .unwrap_or_else(|| "anonymous".to_string());
            // Collect field initializers up-front. JS semantics: field
            // initializers run before the explicit constructor body with
            // `this` already bound. We model that by either prepending them
            // to the explicit constructor or, when there is none, by emitting
            // a synthetic `<Class>.constructor` topology that just runs them.
            let mut field_inits: Vec<(String, Node, String)> = vec![];
            let mut has_explicit_ctor = false;
            if let Some(body) = node.child_by_field_name("body") {
                for i in 0..body.named_child_count() {
                    if let Some(c) = body.named_child(i) {
                        match c.kind() {
                            "public_field_definition" | "field_definition" => {
                                if let (Some(name_node), Some(value_node)) = (
                                    c.child_by_field_name("name"),
                                    c.child_by_field_name("value"),
                                ) {
                                    let fname = node_text(name_node, source);
                                    let value_text = node_text(value_node, source);
                                    field_inits.push((fname, value_node, value_text));
                                }
                            }
                            "method_definition" => {
                                if get_function_name(&c, source).as_deref() == Some("constructor") {
                                    has_explicit_ctor = true;
                                }
                            }
                            _ => {}
                        }
                    }
                }
            }
            // Extract each method with `<ClassName>.<methodName>` as the
            // topology key so gnexec can dispatch `obj.method()` without
            // colliding across classes that share method names.
            if let Some(body) = node.child_by_field_name("body") {
                for i in 0..body.named_child_count() {
                    if let Some(c) = body.named_child(i) {
                        if c.kind() == "method_definition" {
                            let method_name = get_function_name(&c, source)
                                .unwrap_or_else(|| "anonymous".to_string());
                            let qualified = format!("{}.{}", class_name, method_name);
                            let mut cfg = extract_function_cfg(
                                &c,
                                source,
                                file_path,
                                &qualified,
                                module_preamble,
                            )?;
                            // Stash the class name on the entry so the
                            // walker can bind `this` + dispatch correctly.
                            if let Some(entry) = cfg.nodes.get_mut(cfg.entry) {
                                entry
                                    .extra_properties
                                    .insert("class_name".to_string(), class_name.clone());
                                entry
                                    .extra_properties
                                    .insert("method_name".to_string(), method_name.clone());
                            }
                            // Prepend field initializers into the explicit
                            // constructor's body — they run before the user
                            // constructor's statements per JS semantics.
                            if method_name == "constructor" && !field_inits.is_empty() {
                                inject_field_inits_into_cfg(
                                    &mut cfg,
                                    &field_inits,
                                    source,
                                    file_path,
                                );
                            }
                            cfgs.push(cfg);
                        }
                    }
                }
            }
            // If the class has fields but no explicit constructor, synthesize
            // a `<Class>.constructor` topology that just runs the field
            // initializers. Without this, `new ClassName()` produces an empty
            // object and any subsequent method call sees `this.field` =
            // undefined — the common real-world bug.
            if !has_explicit_ctor && !field_inits.is_empty() {
                let qualified = format!("{}.constructor", class_name);
                let cfg = synthesize_field_init_constructor(
                    &qualified,
                    &class_name,
                    &field_inits,
                    source,
                    file_path,
                )?;
                cfgs.push(cfg);
            }
            return Ok(());
        }
        "function_declaration" | "method_definition" | "function" => {
            let name = get_function_name(node, source).unwrap_or_else(|| "anonymous".to_string());
            let cfg = extract_function_cfg(node, source, file_path, &name, module_preamble)?;
            cfgs.push(cfg);
        }
        // `function* name() { ... }` — generators emit a regular topology
        // with a CFG post-pass that turns `yield E` into `__yields.push(E)`
        // and rewrites all returns to `return __yields`. This loses lazy
        // semantics but is correct for finite generators (the streaming /
        // iterator majority); coroutine support can come later behind a
        // feature flag. Async generators (`async function*`) flow through
        // here too — `await` already evaluates synchronously in gnexec.
        "generator_function_declaration" => {
            let name = get_function_name(node, source).unwrap_or_else(|| "anonymous".to_string());
            let mut cfg = extract_function_cfg(node, source, file_path, &name, module_preamble)?;
            rewrite_generator_cfg(&mut cfg, file_path, node);
            cfgs.push(cfg);
        }
        "arrow_function" | "function_expression" => {
            // Only extract top-level or named arrow functions.
            if let Some(parent) = node.parent() {
                if parent.kind() == "variable_declarator" {
                    let name = parent
                        .child_by_field_name("name")
                        .map(|n| node_text(n, source))
                        .unwrap_or_else(|| "anonymous".to_string());
                    let cfg =
                        extract_function_cfg(node, source, file_path, &name, module_preamble)?;
                    cfgs.push(cfg);
                }
            }
        }
        "export_statement" => {
            // Look for exported function declarations.
            for i in 0..node.child_count() {
                if let Some(child) = node.child(i) {
                    extract_functions_recursive(&child, source, file_path, cfgs, module_preamble)?;
                }
            }
            return Ok(());
        }
        _ => {}
    }

    // Recurse into children (but not into nested functions we've already extracted).
    for i in 0..node.child_count() {
        if let Some(child) = node.child(i) {
            let kind = child.kind();
            if kind != "function_declaration"
                && kind != "method_definition"
                && kind != "function"
                && kind != "arrow_function"
                && kind != "function_expression"
            {
                extract_functions_recursive(&child, source, file_path, cfgs, module_preamble)?;
            } else if kind == "function_declaration" || kind == "method_definition" {
                // These are top-level, extract them.
                extract_functions_recursive(&child, source, file_path, cfgs, module_preamble)?;
            }
        }
    }

    Ok(())
}

fn extract_function_cfg(
    func_node: &Node,
    source: &str,
    file_path: &str,
    name: &str,
    module_preamble: Option<&str>,
) -> Result<ControlFlowGraph> {
    let mut cfg = ControlFlowGraph::new(
        name.to_string(),
        "typescript".to_string(),
        file_path.to_string(),
    );

    // Extract TypeScript function signature.
    let func_text = node_text(*func_node, source);
    cfg.signature.is_async = func_text.starts_with("async ");
    cfg.signature.is_generator = func_text.contains("function*");

    // Extract parameters.
    if let Some(params_node) = func_node.child_by_field_name("parameters") {
        extract_ts_params(&params_node, source, &mut cfg.signature.params);
    }
    // Extract return type.
    if let Some(ret_type) = func_node.child_by_field_name("return_type") {
        cfg.signature.return_type = Some(
            node_text(ret_type, source)
                .trim_start_matches(':')
                .trim()
                .to_string(),
        );
    }
    // Extract callees.
    if let Some(body_node) = func_node.child_by_field_name("body") {
        extract_ts_callees(&body_node, source, &mut cfg.signature.callees);
    }

    let mut entry_props = ir_build_entry_props(&cfg.signature.params);
    if let Some(preamble_json) = module_preamble {
        entry_props.insert("module_preamble".to_string(), preamble_json.to_string());
    }
    let entry = cfg.add_node_with_props(
        CfgNodeKind::Entry {
            name: name.to_string(),
        },
        SourceSpan::from_tree_sitter(file_path, func_node),
        format!("function {name}"),
        entry_props,
    );
    cfg.entry = entry;

    let body = func_node.child_by_field_name("body").unwrap_or(*func_node);

    let last = extract_body_cfg(&body, source, file_path, &mut cfg, entry)?;

    // Add implicit return if needed.
    if let Some(last_id) = last {
        let last_node = &cfg.nodes[last_id];
        if !matches!(last_node.kind, CfgNodeKind::Return) {
            let ret = cfg.add_node(
                CfgNodeKind::Return,
                SourceSpan::from_tree_sitter(file_path, &body),
                "implicit return".to_string(),
            );
            cfg.add_edge(last_id, ret, None);
            cfg.exits.push(ret);
        }
    } else {
        let ret = cfg.add_node(
            CfgNodeKind::Return,
            SourceSpan::from_tree_sitter(file_path, &body),
            "implicit return".to_string(),
        );
        cfg.add_edge(entry, ret, None);
        cfg.exits.push(ret);
    }

    Ok(cfg)
}

/// Top-level statement kinds that count as an "imperative script" — i.e. code
/// that executes when the module loads, as opposed to pure declarations,
/// types, imports, or hoisted function definitions (which `extract_functions_*`
/// already turns into their own topologies). Only the presence of one of these
/// justifies synthesizing a `__module_main__` entry.
fn is_executable_top_level(kind: &str) -> bool {
    matches!(
        kind,
        "expression_statement"
            | "if_statement"
            | "switch_statement"
            | "for_statement"
            | "for_in_statement"
            | "while_statement"
            | "do_statement"
            | "try_statement"
            | "throw_statement"
            | "return_statement"
            // A top-level `const x = await fetch(...)` or `const r = run()` is
            // itself a load-time side effect; treat declarations whose
            // initializer is a call/await as executable. (Plain literal consts
            // are already lifted into the module preamble and need no main.)
            | "lexical_declaration"
            | "variable_declaration"
    )
}

/// Returns true if a `lexical_declaration` / `variable_declaration` node has at
/// least one initializer that is a call or await (i.e. a load-time effect), as
/// opposed to plain literal/identifier consts already covered by the module
/// preamble. Conservative: any declarator whose value subtree contains a
/// `call_expression`/`await_expression` qualifies.
fn declaration_has_effect(node: &Node, source: &str) -> bool {
    let text = node_text(*node, source);
    // Cheap structural check: an effectful initializer mentions a call or await.
    // The CFG walker re-parses the IR precisely; this only gates *whether* we
    // bother synthesizing a main, so a substring heuristic is acceptable and
    // additive (false positives just create a harmless extra topology).
    text.contains('(') || text.contains("await ")
}

/// Synthesize a `__module_main__` topology whose body is the program's
/// top-level statements, when those statements are imperative (a script) rather
/// than only declarations/imports/types/functions.
///
/// Returns `None` when there is nothing imperative to run, so pure-library and
/// analysis-mode behavior is unchanged (no extra topology emitted).
fn extract_module_main_cfg(
    root: &Node,
    source: &str,
    file_path: &str,
    module_preamble: Option<&str>,
) -> Result<Option<ControlFlowGraph>> {
    // Decide whether the file has imperative top-level code worth running.
    let mut has_executable = false;
    let mut cursor = root.walk();
    for child in root.named_children(&mut cursor) {
        let kind = child.kind();
        if matches!(kind, "lexical_declaration" | "variable_declaration") {
            if declaration_has_effect(&child, source) {
                has_executable = true;
                break;
            }
        } else if is_executable_top_level(kind) {
            has_executable = true;
            break;
        } else if kind == "export_statement" {
            // `export const X = run()` / `export default run()` can be a
            // load-time effect too.
            let mut inner = child.walk();
            for c in child.named_children(&mut inner) {
                if (matches!(c.kind(), "lexical_declaration" | "variable_declaration")
                    && declaration_has_effect(&c, source))
                    || is_executable_top_level(c.kind())
                {
                    has_executable = true;
                    break;
                }
            }
            if has_executable {
                break;
            }
        }
    }

    if !has_executable {
        return Ok(None);
    }

    let name = "__module_main__";
    let mut cfg = ControlFlowGraph::new(
        name.to_string(),
        "typescript".to_string(),
        file_path.to_string(),
    );
    // A top-level `await` makes the module body async; gnexec evaluates `await`
    // synchronously regardless, but flag it for fidelity.
    cfg.signature.is_async = source.contains("await ");

    // The module main takes no params; still attach the module preamble so the
    // top-level const bindings are in scope when the body runs (the walker
    // seeds module scope from the Entry preamble).
    let mut entry_props = ir_build_entry_props(&cfg.signature.params);
    if let Some(preamble_json) = module_preamble {
        entry_props.insert("module_preamble".to_string(), preamble_json.to_string());
    }
    let entry = cfg.add_node_with_props(
        CfgNodeKind::Entry {
            name: name.to_string(),
        },
        SourceSpan::from_tree_sitter(file_path, root),
        format!("module main {file_path}"),
        entry_props,
    );
    cfg.entry = entry;

    // Treat the program root exactly like a function body: extract_body_cfg
    // iterates the root's children and already skips imports/types/function
    // declarations while emitting Statement/Branch/loop nodes for the rest.
    let last = extract_body_cfg(root, source, file_path, &mut cfg, entry)?;

    // Add an implicit `return null` so the walker has a clean exit. CRITICAL:
    // unlike extract_function_cfg (whose implicit-return span is a
    // `statement_block` the Return byte-range path recognizes as a void
    // function), the module main has no enclosing block — its span would be the
    // `program` node. A property-less Return would then take gnexec's
    // byte-range fallback, re-parse `program`, and re-execute every top-level
    // statement a SECOND time. Emitting an explicit `expr: null` IR forces the
    // IR path (`eval_ir(null)`), so the body runs exactly once.
    let null_return_props =
        ir_build_return_props(serde_json::json!({ "kind": "literal", "value": null }));
    if let Some(last_id) = last {
        let last_node = &cfg.nodes[last_id];
        if !matches!(last_node.kind, CfgNodeKind::Return) {
            let ret = cfg.add_node_with_props(
                CfgNodeKind::Return,
                SourceSpan::from_tree_sitter(file_path, root),
                "implicit module return".to_string(),
                null_return_props,
            );
            cfg.add_edge(last_id, ret, None);
            cfg.exits.push(ret);
        }
    } else {
        let ret = cfg.add_node_with_props(
            CfgNodeKind::Return,
            SourceSpan::from_tree_sitter(file_path, root),
            "implicit module return".to_string(),
            null_return_props,
        );
        cfg.add_edge(entry, ret, None);
        cfg.exits.push(ret);
    }

    Ok(Some(cfg))
}

/// Generator-function post-pass. Lower `function*` semantics to
/// collect-all-yields:
///   * Prepend a Statement after `cfg.entry` that binds `__yields = []`.
///   * Rewrite every node carrying a top-level `{kind:"yield", arg}` IR into
///     a `__yields.push(<arg>)` call statement.
///   * Rewrite every Return's `expr` IR to `__yields` (regardless of the
///     original return value — a return inside a generator is just an early
///     exit; the iterator protocol uses `return.value` only conventionally).
///
/// This is a structural rewrite of `extra_properties.expr` (and the derived
/// `callee` / `args` properties); it does not change CFG topology except for
/// the single inserted init Statement. Callers iterating the resulting array
/// (`for (const v of gen()) ...`) work unchanged via gnexec's existing
/// iterable machinery; `for await` works because gnexec evaluates `await`
/// synchronously.
fn rewrite_generator_cfg(cfg: &mut ControlFlowGraph, file_path: &str, func_node: &Node) {
    use serde_json::{json, Value};

    cfg.signature.is_generator = true;

    // 1. Insert `let __yields = []` between entry and its current successors.
    let init_props =
        ir_build_declaration_props("__yields", json!({ "kind": "array", "items": [] }));
    let init_id = cfg.add_node_with_props(
        CfgNodeKind::Statement,
        SourceSpan::from_tree_sitter(file_path, func_node),
        "let __yields = []".to_string(),
        init_props,
    );
    let entry = cfg.entry;
    // Re-route all edges leaving entry to leave init instead.
    for edge in cfg.edges.iter_mut() {
        if edge.from == entry {
            edge.from = init_id;
        }
    }
    cfg.add_edge(entry, init_id, None);

    // 2. Walk every node and rewrite yield/Return semantics.
    for node in cfg.nodes.iter_mut() {
        let is_return = matches!(node.kind, CfgNodeKind::Return);

        // Parse existing expr IR (if any).
        let parsed_expr: Option<Value> = node
            .extra_properties
            .get("expr")
            .and_then(|s| serde_json::from_str(s).ok());

        if is_return {
            // `return …;` becomes `return __yields;` — the original return
            // value is dropped intentionally (see doc comment above).
            let yields_ident = json!({ "kind": "ident", "name": "__yields" });
            if let Ok(s) = serde_json::to_string(&yields_ident) {
                node.extra_properties.insert("expr".to_string(), s);
            }
            // Strip stale call-shape hints if any.
            node.extra_properties.remove("callee");
            node.extra_properties.remove("args");
            continue;
        }

        // Statement-level yield -> __yields.push(arg).
        let Some(ir) = parsed_expr else { continue };
        let is_yield = ir.get("kind").and_then(Value::as_str) == Some("yield");
        if !is_yield {
            continue;
        }
        let arg = ir.get("arg").cloned().unwrap_or(Value::Null);
        let push_call = json!({
            "kind": "call",
            "callee": {
                "kind": "member",
                "obj": { "kind": "ident", "name": "__yields" },
                "prop": "push",
            },
            "args": [arg],
        });
        if let Ok(s) = serde_json::to_string(&push_call) {
            node.extra_properties.insert("expr".to_string(), s);
        }
        // Update derived call-shape hints (build_expression_statement_props
        // serializes the callee as the dotted string and args as a JSON
        // array). Drop them — the IR walker can derive call shape from
        // `expr`, and the original hints reflected the yield arg's call
        // shape, not the synthetic push.
        node.extra_properties.remove("callee");
        node.extra_properties.remove("args");
    }
}

/// Unwrap an `else_clause` to the actual alternative node (an `if_statement`,
/// `statement_block`, or a single statement). The TS grammar's `alternative`
/// field always points at the `else_clause` wrapper, whose children include
/// the literal `else` keyword.
fn unwrap_else_clause<'a>(node: &Node<'a>) -> Node<'a> {
    if node.kind() != "else_clause" {
        return *node;
    }
    let mut cursor = node.walk();
    if let Some(child) = node.named_children(&mut cursor).next() {
        // The first named child is the actual alternative.
        return child;
    }
    *node
}

/// Extract the CFG for an if-branch body (consequence or unwrapped else target).
/// If the body is a `statement_block`, fall through to `extract_body_cfg` which
/// iterates child statements. Otherwise treat the node itself as a single
/// statement so we don't iterate its tokens (e.g. `return`, string, `;`)
/// and emit them as separate Statement CFG nodes.
fn extract_branch_body_cfg(
    body: &Node,
    source: &str,
    file_path: &str,
    cfg: &mut ControlFlowGraph,
    predecessor: usize,
) -> Result<Option<usize>> {
    if body.kind() == "statement_block" {
        return extract_body_cfg(body, source, file_path, cfg, predecessor);
    }
    extract_single_statement_cfg(body, source, file_path, cfg, predecessor)
}

/// Extract a single statement (not wrapped in a block) into the CFG. Mirrors
/// the per-child arms in `extract_body_cfg`, but operates on the statement
/// node itself rather than iterating children.
fn extract_single_statement_cfg(
    stmt: &Node,
    source: &str,
    file_path: &str,
    cfg: &mut ControlFlowGraph,
    predecessor: usize,
) -> Result<Option<usize>> {
    let kind = stmt.kind();
    match kind {
        "if_statement"
        | "switch_statement"
        | "for_statement"
        | "for_in_statement"
        | "while_statement"
        | "do_statement"
        | "try_statement"
        | "return_statement"
        | "expression_statement"
        | "lexical_declaration"
        | "variable_declaration"
        | "throw_statement" => {
            // Wrap into a synthetic single-element body by reusing extract_body_cfg
            // on a parent-like iteration. Since we can't synthesize a Node,
            // inline the same dispatch here.
        }
        _ => {}
    }

    // Reuse the dispatch logic from extract_body_cfg by calling it with a
    // pseudo body where we manually invoke the relevant arm. Simplest: emit
    // a Statement for any non-control-flow statement, and handle the control
    // flow shapes explicitly.
    let mut current = predecessor;
    match kind {
        "return_statement" => {
            let extra = build_return_props(stmt, source);
            let ret = cfg.add_node_with_props(
                CfgNodeKind::Return,
                SourceSpan::from_tree_sitter(file_path, stmt),
                node_text_truncated(stmt, source, 60),
                extra,
            );
            cfg.add_edge(current, ret, None);
            cfg.exits.push(ret);
            Ok(Some(ret))
        }
        "throw_statement" => {
            let n = cfg.add_node(
                CfgNodeKind::Return,
                SourceSpan::from_tree_sitter(file_path, stmt),
                node_text_truncated(stmt, source, 60),
            );
            cfg.add_edge(current, n, None);
            cfg.exits.push(n);
            Ok(Some(n))
        }
        "expression_statement" => {
            let node_kind = classify_expression(stmt, source);
            let extra = build_expression_statement_props(stmt, source);
            let s = cfg.add_node_with_props(
                node_kind,
                SourceSpan::from_tree_sitter(file_path, stmt),
                node_text_truncated(stmt, source, 60),
                extra,
            );
            cfg.add_edge(current, s, None);
            current = s;
            Ok(Some(current))
        }
        "lexical_declaration" | "variable_declaration" => {
            let node_kind = classify_declaration(stmt, source);
            let extra = build_declaration_props(stmt, source);
            let s = cfg.add_node_with_props(
                node_kind,
                SourceSpan::from_tree_sitter(file_path, stmt),
                node_text_truncated(stmt, source, 60),
                extra,
            );
            cfg.add_edge(current, s, None);
            current = s;
            Ok(Some(current))
        }
        // For nested control flow (if/switch/loops/try) inside a brace-less
        // branch (e.g. `if (a) if (b) ...`), defer to the iterating dispatcher
        // by treating this node as a one-element body.
        "if_statement" | "switch_statement" | "for_statement" | "for_in_statement"
        | "while_statement" | "do_statement" | "try_statement" => {
            extract_body_cfg_single(stmt, source, file_path, cfg, predecessor)
        }
        _ => {
            // Generic fall-through: emit one Statement for the whole node.
            let s = cfg.add_node(
                CfgNodeKind::Statement,
                SourceSpan::from_tree_sitter(file_path, stmt),
                node_text_truncated(stmt, source, 60),
            );
            cfg.add_edge(current, s, None);
            current = s;
            Ok(Some(current))
        }
    }
}

/// Drive the existing per-kind dispatch in `extract_body_cfg` for a single
/// child node by temporarily wrapping it. We achieve this by calling
/// `extract_body_cfg` on the node itself when it has named children that
/// match the dispatch (control-flow statements always do).
/// Build the `expr` IR property for an `if_statement`'s condition so the Branch
/// is evaluated IR-first at runtime, independent of source byte offsets. Without
/// this, a Branch whose source span is unreliable (e.g. inside a re-parsed arrow
/// body) fell back to a byte-range tree-sitter scan and failed with
/// "Branch has no if_statement". Mirrors the switch/else-if lowering, which
/// already attach `expr`.
fn if_condition_props(stmt: &Node, source: &str) -> std::collections::BTreeMap<String, String> {
    let mut props: std::collections::BTreeMap<String, String> = std::collections::BTreeMap::new();
    if let Some(cond) = stmt.child_by_field_name("condition") {
        // TS wraps the condition in a `parenthesized_expression`; lower the inner expr.
        let inner = cond.named_child(0).unwrap_or(cond);
        if let Ok(s) = serde_json::to_string(&ts_node_to_ir(&inner, source)) {
            props.insert("expr".to_string(), s);
        }
    }
    props
}

fn extract_body_cfg_single(
    stmt: &Node,
    source: &str,
    file_path: &str,
    cfg: &mut ControlFlowGraph,
    predecessor: usize,
) -> Result<Option<usize>> {
    // We want to invoke the matching arm of extract_body_cfg for this single
    // statement. Inline-calling extract_body_cfg with `body=stmt` would iterate
    // its child tokens — wrong. Instead, build an ad-hoc dispatcher mirroring
    // the if/switch/loop/try arms.
    let kind = stmt.kind();
    let mut current = predecessor;
    match kind {
        "if_statement" => {
            let branch = cfg.add_node_with_props(
                CfgNodeKind::Branch {
                    exhaustive: stmt.child_by_field_name("alternative").is_some(),
                },
                SourceSpan::from_tree_sitter(file_path, stmt),
                node_text_truncated(stmt, source, 40),
                if_condition_props(stmt, source),
            );
            cfg.add_edge(current, branch, None);
            let merge = cfg.add_node(
                CfgNodeKind::Merge,
                SourceSpan::from_tree_sitter(file_path, stmt),
                "if merge".to_string(),
            );
            if let Some(consequence) = stmt.child_by_field_name("consequence") {
                let then_end =
                    extract_branch_body_cfg(&consequence, source, file_path, cfg, branch)?;
                if let Some(te) = then_end {
                    cfg.add_edge(te, merge, None);
                }
            }
            if let Some(alternative) = stmt.child_by_field_name("alternative") {
                let else_target = unwrap_else_clause(&alternative);
                let else_end =
                    extract_branch_body_cfg(&else_target, source, file_path, cfg, branch)?;
                if let Some(ee) = else_end {
                    cfg.add_edge(ee, merge, None);
                }
            } else {
                cfg.add_edge(branch, merge, Some("no-else".into()));
            }
            current = merge;
            Ok(Some(current))
        }
        // For other control flow shapes inside a brace-less alternative,
        // fall back to a generic Statement so we don't drop them entirely.
        // These are uncommon in practice (`if (a) for (...) { ... }` etc.).
        _ => {
            let s = cfg.add_node(
                CfgNodeKind::Statement,
                SourceSpan::from_tree_sitter(file_path, stmt),
                node_text_truncated(stmt, source, 60),
            );
            cfg.add_edge(current, s, None);
            current = s;
            Ok(Some(current))
        }
    }
}

fn extract_body_cfg(
    body: &Node,
    source: &str,
    file_path: &str,
    cfg: &mut ControlFlowGraph,
    predecessor: usize,
) -> Result<Option<usize>> {
    let mut current = predecessor;

    for i in 0..body.child_count() {
        let child = match body.child(i) {
            Some(c) => c,
            None => continue,
        };

        match child.kind() {
            "if_statement" => {
                let branch = cfg.add_node_with_props(
                    CfgNodeKind::Branch {
                        exhaustive: child.child_by_field_name("alternative").is_some(),
                    },
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 40),
                    if_condition_props(&child, source),
                );
                cfg.add_edge(current, branch, None);

                let merge = cfg.add_node(
                    CfgNodeKind::Merge,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    "if merge".to_string(),
                );

                // Then branch. The `consequence` field may be either a block
                // (`statement_block`) or a single statement (`if (c) return …;`).
                // Use the unwrapping helper so single-statement bodies are
                // handled as one statement rather than as a sequence of
                // tokens like `return`, the string literal, and `;`.
                if let Some(consequence) = child.child_by_field_name("consequence") {
                    let then_end =
                        extract_branch_body_cfg(&consequence, source, file_path, cfg, branch)?;
                    if let Some(te) = then_end {
                        cfg.add_edge(te, merge, None);
                    }
                }

                // Else branch. tree-sitter wraps the alternative in an
                // `else_clause` whose children are the literal `else` keyword
                // followed by the actual statement (an `if_statement` for
                // chained `else if`, or a block / single statement). Unwrap
                // so we don't emit a spurious Statement for the `else` token,
                // which would later confuse gnexec's `climb_to_statement`
                // walker into landing on the program root.
                if let Some(alternative) = child.child_by_field_name("alternative") {
                    let else_target = unwrap_else_clause(&alternative);
                    let else_end =
                        extract_branch_body_cfg(&else_target, source, file_path, cfg, branch)?;
                    if let Some(ee) = else_end {
                        cfg.add_edge(ee, merge, None);
                    }
                } else {
                    // No else: branch can skip directly to merge.
                    cfg.add_edge(branch, merge, Some("no-else".into()));
                }

                current = merge;
            }

            "switch_statement" => {
                // Lower `switch (subject) { case A: ...; case B: ...; default: ...; }`
                // into a chain of Branch nodes whose `expr` IR property carries
                // `{kind:"binary", op:"===", lhs:<subject_ir>, rhs:<case_value_ir>}`.
                // This lets gnexec evaluate the dispatch directly from IR rather than
                // trying to byte-range-parse a `switch_statement` it can't unpack.
                //
                // Fall-through contract (matches JS semantics for the common cases):
                //   - case body terminates with break/return/throw/continue → wires
                //     to the post-switch merge, no fall-through.
                //   - empty case (`case 'a':` with no body) and case body without a
                //     terminator → control falls into the next case's body via a
                //     PROCESS edge.
                //   - default clause is the else branch of the final case's branch;
                //     if no default, the false path of the last branch goes to merge.
                current = lower_switch_statement(&child, source, file_path, cfg, current)?;
            }

            "for_statement" | "for_in_statement" | "while_statement" | "do_statement" => {
                let bounded = is_bounded_loop(&child, source);
                let loop_node = cfg.add_node(
                    CfgNodeKind::Loop { bounded },
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 40),
                );
                cfg.add_edge(current, loop_node, None);

                if let Some(loop_body) = child.child_by_field_name("body") {
                    // For brace-less single-statement bodies (e.g.
                    // `for (const g of A) if (B.has(g)) inter++;`), we MUST
                    // dispatch via extract_branch_body_cfg — extract_body_cfg
                    // would iterate the bare statement's tokens
                    // (`if`, `(`, condition, `)`, body) instead of treating
                    // the whole thing as one statement, mis-walking the
                    // iteration (gap #23 in docs/pneuma/gnexec-fixes.md).
                    let body_end = extract_branch_body_cfg(
                        &loop_body, source, file_path, cfg, loop_node,
                    )?;
                    if let Some(be) = body_end {
                        // Back edge (loop).
                        cfg.add_edge(be, loop_node, Some("back".into()));
                    }
                }

                let loop_exit = cfg.add_node(
                    CfgNodeKind::Merge,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    "loop exit".to_string(),
                );
                cfg.add_edge(loop_node, loop_exit, Some("exit".into()));
                current = loop_exit;
            }

            "try_statement" => {
                let try_entry = cfg.add_node(
                    CfgNodeKind::TryEntry,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    "try".to_string(),
                );
                cfg.add_edge(current, try_entry, None);

                let merge = cfg.add_node(
                    CfgNodeKind::Merge,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    "try merge".to_string(),
                );

                // Try body.
                if let Some(try_body) = child.child_by_field_name("body") {
                    let try_end = extract_body_cfg(&try_body, source, file_path, cfg, try_entry)?;
                    if let Some(te) = try_end {
                        cfg.add_edge(te, merge, None);
                    }
                }

                // Catch handler.
                if let Some(handler) = child.child_by_field_name("handler") {
                    let catch_node = cfg.add_node(
                        CfgNodeKind::CatchHandler,
                        SourceSpan::from_tree_sitter(file_path, &handler),
                        "catch".to_string(),
                    );
                    cfg.add_exceptional_edge(try_entry, catch_node, Some("error".into()));

                    if let Some(catch_body) = handler.child_by_field_name("body") {
                        let catch_end =
                            extract_body_cfg(&catch_body, source, file_path, cfg, catch_node)?;
                        if let Some(ce) = catch_end {
                            cfg.add_edge(ce, merge, None);
                        }
                    }
                }

                // Finally.
                if let Some(finalizer) = child.child_by_field_name("finalizer") {
                    let finally_node = cfg.add_node(
                        CfgNodeKind::FinallyHandler,
                        SourceSpan::from_tree_sitter(file_path, &finalizer),
                        "finally".to_string(),
                    );
                    cfg.add_edge(merge, finally_node, None);

                    // The `finalizer` is a tree-sitter `finally_clause`
                    // (`finally` keyword + `body` statement_block). Lower its
                    // `body` block — NOT the clause itself. Passing the whole
                    // clause to extract_body_cfg iterates [finally-keyword,
                    // statement_block] and falls into the generic catchall,
                    // emitting two bogus Statement nodes (the `finally` token
                    // and the unexpanded block) with spans covering the keyword
                    // and the `{}` — neither runs the finalizer's real
                    // statements, and the whole-clause spans make byte-range
                    // exec re-enter the parent try (infinite re-walk). Unwrap to
                    // the `body` statement_block exactly like the catch handler
                    // above so finalizer statements get their OWN tight spans.
                    let finally_body = finalizer
                        .child_by_field_name("body")
                        .unwrap_or(finalizer);
                    let finally_end =
                        extract_body_cfg(&finally_body, source, file_path, cfg, finally_node)?;
                    current = finally_end.unwrap_or(finally_node);
                } else {
                    current = merge;
                }
            }

            "return_statement" => {
                let extra = build_return_props(&child, source);
                let ret = cfg.add_node_with_props(
                    CfgNodeKind::Return,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 60),
                    extra,
                );
                cfg.add_edge(current, ret, None);
                cfg.exits.push(ret);
                return Ok(Some(ret));
            }

            "expression_statement" => {
                let node_kind = classify_expression(&child, source);
                let extra = build_expression_statement_props(&child, source);
                let stmt = cfg.add_node_with_props(
                    node_kind,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 60),
                    extra,
                );
                cfg.add_edge(current, stmt, None);
                current = stmt;
            }

            "lexical_declaration" | "variable_declaration" => {
                let node_kind = classify_declaration(&child, source);
                let extra = build_declaration_props(&child, source);
                let stmt = cfg.add_node_with_props(
                    node_kind,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 60),
                    extra,
                );
                cfg.add_edge(current, stmt, None);
                current = stmt;
            }

            "throw_statement" => {
                let stmt = cfg.add_node(
                    CfgNodeKind::Return, // throw is like an exceptional return
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 60),
                );
                cfg.add_edge(current, stmt, None);
                cfg.exits.push(stmt);
                return Ok(Some(stmt));
            }

            // Skip non-statement nodes.
            "comment"
            | "{"
            | "}"
            | ";"
            | ","
            | "type_alias_declaration"
            | "interface_declaration"
            | "import_statement"
            | "export_statement"
            // JS hoists function declarations — they're not runtime statements
            // that execute in source order. Skipping prevents the extractor
            // from emitting a Statement with a degenerate source range and a
            // malformed `callee='function fooname'` property that gnexec then
            // fails to evaluate as IR-or-byte-range.
            | "function_declaration"
            | "function_signature"
            | "generator_function_declaration" => {}

            _ => {
                // Generic statement.
                let stmt = cfg.add_node(
                    CfgNodeKind::Statement,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 60),
                );
                cfg.add_edge(current, stmt, None);
                current = stmt;
            }
        }
    }

    Ok(Some(current))
}

/// Lower a tree-sitter `switch_statement` into a Branch-chain CFG.
///
/// For each `switch_case` we emit a `Branch` node whose `extra_properties.expr`
/// carries canonical IR for `subject === case_value`. The true edge points at
/// the case body's entry; the false edge chains to the next case's branch (or
/// to the default body / post-switch merge).
///
/// Fall-through: if a case body does not end in a terminator (break, return,
/// throw, continue) we add an explicit PROCESS edge from the case body's
/// linear end into the next case's body entry, matching JS semantics.
///
/// Empty case (no `body` field, e.g. `case 'a':` clusters) → its body entry
/// is identical to the next case's body entry via a 0-statement chain.
fn lower_switch_statement(
    switch_node: &Node,
    source: &str,
    file_path: &str,
    cfg: &mut ControlFlowGraph,
    predecessor: usize,
) -> Result<usize> {
    use serde_json::json;

    // Resolve the switch subject IR (parenthesized_expression unwraps in
    // ts_node_to_ir already).
    let subject_ir = switch_node
        .child_by_field_name("value")
        .map(|n| ts_node_to_ir(&n, source))
        .unwrap_or(serde_json::Value::Null);

    // Allocate the post-switch merge up front so every terminating path can
    // target it.
    let post_merge = cfg.add_node(
        CfgNodeKind::Merge,
        SourceSpan::from_tree_sitter(file_path, switch_node),
        "switch merge".to_string(),
    );

    // Collect cases (preserving order). Each entry is (case_node, is_default).
    let mut cases: Vec<(Node, bool)> = Vec::new();
    if let Some(body_node) = switch_node.child_by_field_name("body") {
        for j in 0..body_node.child_count() {
            if let Some(case) = body_node.child(j) {
                match case.kind() {
                    "switch_case" => cases.push((case, false)),
                    "switch_default" => cases.push((case, true)),
                    _ => {}
                }
            }
        }
    }

    // Empty switch: just wire predecessor straight to merge.
    if cases.is_empty() {
        cfg.add_edge(predecessor, post_merge, Some("empty-switch".into()));
        return Ok(post_merge);
    }

    // Pre-allocate body entry nodes for each case so empty cases (`case 'c':`
    // with no body) and chained fall-through can target the next case's body
    // by node-id without a forward reference dance.
    let mut body_entries: Vec<usize> = Vec::with_capacity(cases.len());
    for (case, _) in &cases {
        body_entries.push(cfg.add_node(
            CfgNodeKind::Merge,
            SourceSpan::from_tree_sitter(file_path, case),
            "case body".to_string(),
        ));
    }

    // Find the index of the default clause (only the first one is meaningful).
    let default_idx = cases.iter().position(|(_, is_default)| *is_default);

    // Emit Branch nodes for non-default cases in order. The false edge of each
    // branch chains to the next non-default branch, or — once we've exhausted
    // non-default cases — to the default body entry (or post_merge if none).
    let mut prev_else: usize = predecessor;
    let mut emitted_branch = false;
    for (i, (case, is_default)) in cases.iter().enumerate() {
        if *is_default {
            continue;
        }
        let case_value_ir = case
            .child_by_field_name("value")
            .map(|n| ts_node_to_ir(&n, source))
            .unwrap_or(serde_json::Value::Null);
        let cmp_ir = json!({
            "kind": "binary",
            "op": "===",
            "lhs": subject_ir.clone(),
            "rhs": case_value_ir,
        });
        let mut props: BTreeMap<String, String> = BTreeMap::new();
        if let Ok(s) = serde_json::to_string(&cmp_ir) {
            props.insert("expr".to_string(), s);
        }
        let branch = cfg.add_node_with_props(
            CfgNodeKind::Branch { exhaustive: false },
            SourceSpan::from_tree_sitter(file_path, case),
            node_text_truncated(case, source, 40),
            props,
        );
        cfg.add_edge(prev_else, branch, None);
        // True edge: enter this case's body.
        cfg.add_edge(branch, body_entries[i], Some("case-match".into()));
        prev_else = branch;
        emitted_branch = true;
    }

    // Wire the final non-default branch's false edge to either the default
    // body or the post-switch merge.
    if emitted_branch {
        if let Some(d) = default_idx {
            cfg.add_edge(prev_else, body_entries[d], Some("default".into()));
        } else {
            cfg.add_edge(prev_else, post_merge, Some("no-default".into()));
        }
    } else if let Some(d) = default_idx {
        // Default-only switch (no real cases). Predecessor needs to flow into
        // the default body directly.
        cfg.add_edge(predecessor, body_entries[d], None);
    } else {
        cfg.add_edge(predecessor, post_merge, None);
    }

    // Now extract each case body. Each case's body chain starts at
    // `body_entries[i]`. If the body terminates linearly (break / return /
    // throw / continue) we wire its tail to `post_merge`; otherwise (implicit
    // fall-through) we wire it into the next case's body entry to match JS
    // semantics.
    for (i, (case, _)) in cases.iter().enumerate() {
        let entry = body_entries[i];
        let (tail, terminated) = extract_case_body(case, source, file_path, cfg, entry)?;

        if terminated {
            // For `break`/`continue` the case body's tail is a Statement node
            // that we still need to wire to the post-switch merge so the
            // path doesn't dead-end. For `return`/`throw` the dispatcher has
            // already pushed the node to `cfg.exits`, but adding an edge to
            // merge is harmless (no successor walk uses it on Return nodes).
            if let Some(t) = tail {
                cfg.add_edge(t, post_merge, Some("break".into()));
            }
            continue;
        }

        // Implicit fall-through: wire tail into the next case's body entry,
        // or to post_merge if this is the last case.
        let target = if i + 1 < body_entries.len() {
            body_entries[i + 1]
        } else {
            post_merge
        };
        if let Some(t) = tail {
            cfg.add_edge(t, target, Some("fallthrough".into()));
        } else {
            // Empty body — entry is its own tail. Chain directly.
            cfg.add_edge(entry, target, Some("fallthrough".into()));
        }
    }

    Ok(post_merge)
}

/// Extract the statements of a `switch_case` / `switch_default` node into the
/// CFG starting at `entry`. Returns `(tail_node, terminated)` where
/// `terminated` is true if the case ended in a control-flow terminator
/// (`break`, `return`, `throw`, `continue`) — in which case the caller MUST
/// NOT add a fall-through edge.
fn extract_case_body(
    case: &Node,
    source: &str,
    file_path: &str,
    cfg: &mut ControlFlowGraph,
    entry: usize,
) -> Result<(Option<usize>, bool)> {
    let mut current = entry;
    let mut cursor = case.walk();
    let mut any = false;
    let mut terminated = false;

    // Walk every child in the `body` field. tree-sitter-typescript marks each
    // statement of a non-blocked case body with `field=body` (one per stmt);
    // a single `statement_block` body shows up as one child instead.
    let body_children: Vec<Node> = case.children_by_field_name("body", &mut cursor).collect();

    for stmt in body_children {
        any = true;
        match stmt.kind() {
            "statement_block" => {
                if let Some(end) = extract_body_cfg(&stmt, source, file_path, cfg, current)? {
                    current = end;
                }
            }
            "break_statement" | "continue_statement" => {
                let n = cfg.add_node(
                    CfgNodeKind::Statement,
                    SourceSpan::from_tree_sitter(file_path, &stmt),
                    node_text_truncated(&stmt, source, 60),
                );
                cfg.add_edge(current, n, None);
                current = n;
                terminated = true;
                break;
            }
            "return_statement" | "throw_statement" => {
                // Reuse the single-statement dispatcher so we get the same
                // expr/callee/args properties as a top-level return/throw.
                let end = extract_single_statement_cfg(&stmt, source, file_path, cfg, current)?;
                if let Some(e) = end {
                    current = e;
                }
                terminated = true;
                break;
            }
            _ => {
                // Anything else: dispatch as a single statement so we don't
                // iterate token children (the bug the old switch lowering hit
                // by calling extract_body_cfg on the `switch_case` node, which
                // walked over `case`, `:`, `;` tokens).
                let end = extract_single_statement_cfg(&stmt, source, file_path, cfg, current)?;
                if let Some(e) = end {
                    current = e;
                }
            }
        }
    }

    if !any {
        // Empty case (e.g. `case 'a':` with no body field) — caller treats
        // `entry` as its own tail and adds the fall-through edge.
        return Ok((None, false));
    }

    Ok((Some(current), terminated))
}

/// Classify an expression statement into a more specific CFG node kind.
fn classify_expression(node: &Node, source: &str) -> CfgNodeKind {
    let text = node_text(*node, source);

    // Detect awaited expressions (sync join).
    if text.contains("await ") {
        return CfgNodeKind::SyncJoin;
    }

    // Detect resource patterns.
    // Note: .connect( alone is too broad -- matches Web Audio node.connect(),
    // GraphQL isConnection, UI state connections, etc. Only match explicit
    // network connection creation patterns.
    let resource_patterns = [
        ("fs.open", ResourceKind::File),
        ("createReadStream", ResourceKind::File),
        ("createWriteStream", ResourceKind::File),
        ("net.connect", ResourceKind::Socket),
        ("net.createConnection", ResourceKind::Socket),
        ("tls.connect", ResourceKind::Socket),
        ("new WebSocket", ResourceKind::Socket),
        ("http.request(", ResourceKind::Connection),
        ("https.request(", ResourceKind::Connection),
    ];

    for (pattern, kind) in &resource_patterns {
        if text.contains(pattern) {
            return CfgNodeKind::ResourceAcquire {
                resource_kind: kind.clone(),
            };
        }
    }

    let close_patterns = [".close(", ".end(", ".destroy(", ".disconnect("];
    for pattern in &close_patterns {
        if text.contains(pattern) {
            return CfgNodeKind::ResourceRelease {
                resource_kind: ResourceKind::Generic("stream".to_string()),
            };
        }
    }

    // Detect spawn patterns.
    // Note: setTimeout/setInterval are NOT concurrent spawns -- they are
    // timer scheduling on the same event loop. Only flag actual thread/process spawns.
    if text.contains("new Worker(")
        || text.contains("child_process.fork(")
        || text.contains("child_process.spawn(")
        || text.contains("cluster.fork(")
    {
        return CfgNodeKind::ConcurrentSpawn;
    }

    CfgNodeKind::Statement
}

/// Classify a variable declaration.
fn classify_declaration(node: &Node, source: &str) -> CfgNodeKind {
    let text = node_text(*node, source);

    // Check for resource acquisition in declaration.
    // Note: readFileSync/writeFileSync are NOT resource acquires -- they are
    // synchronous operations that open, read/write, and close in one call.
    let resource_patterns = [
        ("fs.open", ResourceKind::File),
        ("createReadStream", ResourceKind::File),
        ("createWriteStream", ResourceKind::File),
        ("createConnection", ResourceKind::Connection),
        ("new Pool(", ResourceKind::Connection),
    ];

    for (pattern, kind) in &resource_patterns {
        if text.contains(pattern) {
            return CfgNodeKind::ResourceAcquire {
                resource_kind: kind.clone(),
            };
        }
    }

    CfgNodeKind::Statement
}

fn get_function_name(node: &Node, source: &str) -> Option<String> {
    node.child_by_field_name("name")
        .map(|n| node_text(n, source))
}

fn extract_ts_params(params_node: &Node, source: &str, params: &mut Vec<FunctionParam>) {
    for i in 0..params_node.child_count() {
        if let Some(child) = params_node.child(i) {
            let kind = child.kind();
            if kind == "required_parameter"
                || kind == "optional_parameter"
                || kind == "rest_pattern"
            {
                let pattern_node = child
                    .child_by_field_name("pattern")
                    .or_else(|| child.child(0));
                // Destructured object/array params (`function f({a, b})`,
                // `function f([x, y])`) bind each key as a separate name in
                // the body scope. Surface each destructured key as its own
                // FunctionParam so gnexec's named-arg binding can pick it
                // up from the input object. Without this, the param.name is
                // the whole pattern text ("{a, b = 0}") and identifiers
                // inside the body resolve as unbound.
                if let Some(pn) = pattern_node {
                    if pn.kind() == "object_pattern" {
                        expand_object_pattern_params(&pn, source, params);
                        continue;
                    } else if pn.kind() == "array_pattern" {
                        expand_array_pattern_params(&pn, source, params);
                        continue;
                    }
                }
                let name = pattern_node
                    .map(|n| node_text(n, source))
                    .unwrap_or_default()
                    .trim_start_matches("...")
                    .to_string();
                let type_ann = child.child_by_field_name("type").map(|n| {
                    node_text(n, source)
                        .trim_start_matches(':')
                        .trim()
                        .to_string()
                });
                let default_val = child
                    .child_by_field_name("value")
                    .map(|n| node_text(n, source));
                let is_variadic =
                    kind == "rest_pattern" || node_text(child, source).starts_with("...");

                if !name.is_empty() {
                    params.push(FunctionParam {
                        name,
                        type_annotation: type_ann,
                        default_value: default_val,
                        is_variadic,
                        semantic_type: Default::default(),
                    });
                }
            } else if kind == "identifier" {
                let name = node_text(child, source);
                if !name.is_empty() && name != "," {
                    params.push(FunctionParam {
                        name,
                        type_annotation: None,
                        default_value: None,
                        is_variadic: false,
                        semantic_type: Default::default(),
                    });
                }
            }
        }
    }
}

/// Flatten an `object_pattern` (TS destructured param `{ a, b = 0, ...rest }`)
/// into individual FunctionParam entries — one per destructured key. Default
/// values from `object_assignment_pattern` are captured so the binder can
/// fall back when the input object lacks the key. Nested patterns are
/// recursed.
fn expand_object_pattern_params(pattern: &Node, source: &str, out: &mut Vec<FunctionParam>) {
    let mut cursor = pattern.walk();
    for child in pattern.named_children(&mut cursor) {
        match child.kind() {
            "shorthand_property_identifier_pattern" | "shorthand_property_identifier" => {
                let name = node_text(child, source);
                if !name.is_empty() {
                    out.push(FunctionParam {
                        name,
                        type_annotation: None,
                        default_value: None,
                        is_variadic: false,
                        semantic_type: Default::default(),
                    });
                }
            }
            "pair_pattern" => {
                // `{ k: alias }` or `{ k: { nested } }`. Bind on the value
                // side; alias inherits the key's input slot via downstream
                // IR. For simple aliases the value is an identifier — emit
                // the alias name. For nested patterns, recurse.
                let value = child.child_by_field_name("value");
                if let Some(v) = value {
                    if v.kind() == "object_pattern" {
                        expand_object_pattern_params(&v, source, out);
                    } else if v.kind() == "array_pattern" {
                        expand_array_pattern_params(&v, source, out);
                    } else {
                        let name = node_text(v, source);
                        if !name.is_empty() {
                            out.push(FunctionParam {
                                name,
                                type_annotation: None,
                                default_value: None,
                                is_variadic: false,
                                semantic_type: Default::default(),
                            });
                        }
                    }
                }
            }
            "object_assignment_pattern" => {
                let left = child.child_by_field_name("left");
                let right = child.child_by_field_name("right");
                if let Some(l) = left {
                    let name = node_text(l, source);
                    if !name.is_empty() {
                        out.push(FunctionParam {
                            name,
                            type_annotation: None,
                            default_value: right.map(|n| node_text(n, source)),
                            is_variadic: false,
                            semantic_type: Default::default(),
                        });
                    }
                }
            }
            "rest_pattern" => {
                let inner = child.named_child(0);
                if let Some(n) = inner {
                    let name = node_text(n, source);
                    if !name.is_empty() {
                        out.push(FunctionParam {
                            name,
                            type_annotation: None,
                            default_value: None,
                            is_variadic: true,
                            semantic_type: Default::default(),
                        });
                    }
                }
            }
            _ => {}
        }
    }
}

/// Flatten an `array_pattern` (TS destructured param `[a, b, ...rest]`) into
/// individual FunctionParam entries. Positional — caller must pass an array.
fn expand_array_pattern_params(pattern: &Node, source: &str, out: &mut Vec<FunctionParam>) {
    let mut cursor = pattern.walk();
    for child in pattern.named_children(&mut cursor) {
        match child.kind() {
            "identifier" | "shorthand_property_identifier" => {
                let name = node_text(child, source);
                if !name.is_empty() {
                    out.push(FunctionParam {
                        name,
                        type_annotation: None,
                        default_value: None,
                        is_variadic: false,
                        semantic_type: Default::default(),
                    });
                }
            }
            "rest_pattern" => {
                if let Some(inner) = child.named_child(0) {
                    let name = node_text(inner, source);
                    if !name.is_empty() {
                        out.push(FunctionParam {
                            name,
                            type_annotation: None,
                            default_value: None,
                            is_variadic: true,
                            semantic_type: Default::default(),
                        });
                    }
                }
            }
            "object_pattern" => expand_object_pattern_params(&child, source, out),
            "array_pattern" => expand_array_pattern_params(&child, source, out),
            _ => {}
        }
    }
}

fn extract_ts_callees(node: &Node, source: &str, callees: &mut Vec<String>) {
    if node.kind() == "call_expression" {
        if let Some(func) = node.child_by_field_name("function") {
            let callee = node_text(func, source);
            if !callee.is_empty() && !callees.contains(&callee) {
                callees.push(callee);
            }
        }
    }
    for i in 0..node.child_count() {
        if let Some(child) = node.child(i) {
            if child.kind() != "function_declaration" && child.kind() != "arrow_function" {
                extract_ts_callees(&child, source, callees);
            }
        }
    }
}

fn node_text(node: Node, source: &str) -> String {
    source[node.start_byte()..node.end_byte()].to_string()
}

fn node_text_truncated(node: &Node, source: &str, max: usize) -> String {
    let full = &source[node.start_byte()..node.end_byte()];
    let first_line = full.lines().next().unwrap_or(full);
    if first_line.len() > max {
        let end = first_line
            .char_indices()
            .nth(max)
            .map(|(i, _)| i)
            .unwrap_or(first_line.len());
        format!("{}...", &first_line[..end])
    } else {
        first_line.to_string()
    }
}

fn is_bounded_loop(node: &Node, source: &str) -> bool {
    let kind = node.kind();
    match kind {
        // for...in / for...of are always bounded (iterate over collection).
        "for_in_statement" => true,
        "for_statement" => {
            let text = node_text(*node, source);
            // C-style for with .length, .size, numeric bound, or collection iteration.
            text.contains(".length")
                || text.contains(".size")
                || text.contains(" of ")
                || text.contains(" in ")
                || text.contains(" < ")
                || text.contains(" <= ")
                || text.contains(" > ")
                || text.contains(" >= ")
        }
        "while_statement" | "do_statement" => {
            // while loops with explicit termination conditions are bounded.
            let text = node_text(*node, source);
            // while (i < n), while (arr.length), while (queue.length > 0), etc.
            text.contains(" < ")
                || text.contains(" <= ")
                || text.contains(" > ")
                || text.contains(" >= ")
                || text.contains(".length")
                || text.contains(".size")
                || text.contains(".hasNext")
                || text.contains("!done")
                || text.contains("!finished")
                || text.contains("!eof")
        }
        _ => false,
    }
}

fn extract_jsx_declarations(
    root: &Node,
    source: &str,
    file_path: &str,
) -> (
    Vec<PolyglotStructuredDeclaration>,
    Vec<PolyglotProofDeclaration>,
) {
    let mut structured: Vec<PolyglotStructuredDeclaration> = Vec::new();
    let mut proofs: Vec<PolyglotProofDeclaration> = Vec::new();
    let mut context_stack: Vec<BTreeMap<String, String>> = vec![default_context_map()];
    walk_jsx_tree(
        root,
        source,
        file_path,
        &mut context_stack,
        &mut structured,
        &mut proofs,
    );

    if proofs.is_empty() {
        proofs.extend(extract_proof_declarations_from_source(source, file_path));
    }

    structured.sort_by(|a, b| compare_source_span(&a.source_span, &b.source_span));
    proofs.sort_by(|a, b| compare_source_span(&a.source_span, &b.source_span));
    (structured, proofs)
}

fn default_context_map() -> BTreeMap<String, String> {
    let mut map = BTreeMap::new();
    map.insert("schema".to_string(), "https://schema.org/".to_string());
    map.insert(
        "rdf".to_string(),
        "http://www.w3.org/1999/02/22-rdf-syntax-ns#".to_string(),
    );
    map.insert(
        "rdfs".to_string(),
        "http://www.w3.org/2000/01/rdf-schema#".to_string(),
    );
    map.insert(
        "xsd".to_string(),
        "http://www.w3.org/2001/XMLSchema#".to_string(),
    );
    map.insert("foaf".to_string(), "http://xmlns.com/foaf/0.1/".to_string());
    map
}

fn compare_source_span(a: &Option<SourceSpan>, b: &Option<SourceSpan>) -> std::cmp::Ordering {
    match (a, b) {
        (Some(sa), Some(sb)) => sa
            .file
            .cmp(&sb.file)
            .then(sa.start_line.cmp(&sb.start_line))
            .then(sa.start_column.cmp(&sb.start_column))
            .then(sa.end_line.cmp(&sb.end_line))
            .then(sa.end_column.cmp(&sb.end_column)),
        (Some(_), None) => std::cmp::Ordering::Less,
        (None, Some(_)) => std::cmp::Ordering::Greater,
        (None, None) => std::cmp::Ordering::Equal,
    }
}

fn walk_jsx_tree(
    node: &Node,
    source: &str,
    file_path: &str,
    context_stack: &mut Vec<BTreeMap<String, String>>,
    structured: &mut Vec<PolyglotStructuredDeclaration>,
    proofs: &mut Vec<PolyglotProofDeclaration>,
) {
    match node.kind() {
        "jsx_element" => {
            let opening = node
                .child_by_field_name("opening_element")
                .or_else(|| find_child_by_kind(node, "jsx_opening_element"));
            let mut pushed = false;

            if let Some(opening_node) = opening {
                let attrs = extract_jsx_attributes(&opening_node, source);
                let (local_context, context_error) = attrs
                    .get("data-sd-context")
                    .map(|raw| parse_context_json(raw))
                    .unwrap_or((None, None));
                let inherited = context_stack
                    .last()
                    .cloned()
                    .unwrap_or_else(default_context_map);
                let mut effective_context = inherited;
                if let Some(local) = local_context {
                    for (key, value) in local {
                        effective_context.insert(key, value);
                    }
                }

                if has_sd_entity_attribute(&attrs) || context_error.is_some() {
                    structured.push(PolyglotStructuredDeclaration {
                        sd_type: attrs.get("data-sd-type").cloned(),
                        sd_id: attrs.get("data-sd-id").cloned(),
                        sd_prop: attrs.get("data-sd-prop").cloned(),
                        sd_ref: attrs.get("data-sd-ref").cloned(),
                        sd_value: attrs.get("data-sd-value").cloned(),
                        sd_lang: attrs.get("data-sd-lang").cloned(),
                        sd_context: effective_context.clone(),
                        sd_context_error: context_error,
                        text_content: extract_jsx_text(node, source),
                        source_span: Some(SourceSpan::from_tree_sitter(file_path, &opening_node)),
                    });
                }

                if let Some(proof) = parse_proof_declaration(
                    &attrs,
                    SourceSpan::from_tree_sitter(file_path, &opening_node),
                ) {
                    proofs.push(proof);
                }

                context_stack.push(effective_context);
                pushed = true;
            }

            for i in 0..node.child_count() {
                if let Some(child) = node.child(i) {
                    if child.kind() == "jsx_opening_element"
                        || child.kind() == "jsx_closing_element"
                    {
                        continue;
                    }
                    walk_jsx_tree(&child, source, file_path, context_stack, structured, proofs);
                }
            }

            if pushed {
                context_stack.pop();
            }
        }
        "jsx_self_closing_element" => {
            let attrs = extract_jsx_attributes(node, source);
            let (local_context, context_error) = attrs
                .get("data-sd-context")
                .map(|raw| parse_context_json(raw))
                .unwrap_or((None, None));
            let inherited = context_stack
                .last()
                .cloned()
                .unwrap_or_else(default_context_map);
            let mut effective_context = inherited;
            if let Some(local) = local_context {
                for (key, value) in local {
                    effective_context.insert(key, value);
                }
            }

            if has_sd_entity_attribute(&attrs) || context_error.is_some() {
                structured.push(PolyglotStructuredDeclaration {
                    sd_type: attrs.get("data-sd-type").cloned(),
                    sd_id: attrs.get("data-sd-id").cloned(),
                    sd_prop: attrs.get("data-sd-prop").cloned(),
                    sd_ref: attrs.get("data-sd-ref").cloned(),
                    sd_value: attrs.get("data-sd-value").cloned(),
                    sd_lang: attrs.get("data-sd-lang").cloned(),
                    sd_context: effective_context,
                    sd_context_error: context_error,
                    text_content: None,
                    source_span: Some(SourceSpan::from_tree_sitter(file_path, node)),
                });
            }

            if let Some(proof) =
                parse_proof_declaration(&attrs, SourceSpan::from_tree_sitter(file_path, node))
            {
                proofs.push(proof);
            }
        }
        _ => {
            for i in 0..node.child_count() {
                if let Some(child) = node.child(i) {
                    walk_jsx_tree(&child, source, file_path, context_stack, structured, proofs);
                }
            }
        }
    }
}

fn find_child_by_kind<'a>(node: &'a Node<'a>, kind: &str) -> Option<Node<'a>> {
    for i in 0..node.child_count() {
        if let Some(child) = node.child(i) {
            if child.kind() == kind {
                return Some(child);
            }
        }
    }
    None
}

fn extract_jsx_attributes(node: &Node, source: &str) -> BTreeMap<String, String> {
    let mut attributes = BTreeMap::new();
    collect_jsx_attributes(node, source, &mut attributes);
    attributes
}

fn collect_jsx_attributes(node: &Node, source: &str, attributes: &mut BTreeMap<String, String>) {
    for i in 0..node.child_count() {
        if let Some(child) = node.child(i) {
            if child.kind() == "jsx_attribute" {
                let name_node = child.child_by_field_name("name").or_else(|| child.child(0));
                let Some(name_node) = name_node else {
                    continue;
                };
                let name = node_text(name_node, source);
                if name.is_empty() {
                    continue;
                }
                let value_node = find_jsx_attribute_value_node(&child, &name_node, source);
                let value = value_node
                    .map(|node| parse_jsx_attribute_value(node, source))
                    .unwrap_or_else(|| "true".to_string());
                attributes.insert(name, value);
                continue;
            }
            collect_jsx_attributes(&child, source, attributes);
        }
    }
}

fn find_jsx_attribute_value_node<'a>(
    attr_node: &'a Node<'a>,
    name_node: &Node,
    source: &str,
) -> Option<Node<'a>> {
    if let Some(value_node) = attr_node.child_by_field_name("value") {
        return Some(value_node);
    }

    for i in 0..attr_node.child_count() {
        let Some(candidate) = attr_node.child(i) else {
            continue;
        };
        if candidate.start_byte() == name_node.start_byte()
            && candidate.end_byte() == name_node.end_byte()
        {
            continue;
        }
        let raw = node_text(candidate, source);
        let trimmed = raw.trim();
        if trimmed.is_empty() || trimmed == "=" {
            continue;
        }
        if candidate.is_named()
            || trimmed.starts_with('"')
            || trimmed.starts_with('\'')
            || trimmed.starts_with('{')
        {
            return Some(candidate);
        }
    }

    None
}

fn parse_jsx_attribute_value(node: Node, source: &str) -> String {
    let raw = node_text(node, source);
    let trimmed = raw.trim();
    if trimmed.starts_with('"') && trimmed.ends_with('"') && trimmed.len() >= 2 {
        return trimmed[1..trimmed.len() - 1].to_string();
    }
    if trimmed.starts_with('\'') && trimmed.ends_with('\'') && trimmed.len() >= 2 {
        return trimmed[1..trimmed.len() - 1].to_string();
    }
    if trimmed.starts_with('{') && trimmed.ends_with('}') && trimmed.len() >= 2 {
        let inner = trimmed[1..trimmed.len() - 1].trim();
        if (inner.starts_with('"') && inner.ends_with('"') && inner.len() >= 2)
            || (inner.starts_with('\'') && inner.ends_with('\'') && inner.len() >= 2)
        {
            return inner[1..inner.len() - 1].to_string();
        }
        return inner.to_string();
    }
    trimmed.to_string()
}

fn parse_context_json(raw: &str) -> (Option<BTreeMap<String, String>>, Option<String>) {
    let parsed: serde_json::Result<serde_json::Value> = serde_json::from_str(raw);
    match parsed {
        Ok(serde_json::Value::Object(obj)) => {
            let mut map = BTreeMap::new();
            for (key, value) in obj {
                if let serde_json::Value::String(iri) = value {
                    map.insert(key, iri);
                } else {
                    return (
                        None,
                        Some(format!("context prefix '{}' must map to a string IRI", key)),
                    );
                }
            }
            (Some(map), None)
        }
        Ok(_) => (None, Some("context must be a JSON object".to_string())),
        Err(error) => (None, Some(error.to_string())),
    }
}

fn has_sd_entity_attribute(attrs: &BTreeMap<String, String>) -> bool {
    attrs
        .keys()
        .any(|key| key.starts_with("data-sd-") && key != "data-sd-context")
}

fn extract_jsx_text(node: &Node, source: &str) -> Option<String> {
    let mut content = String::new();
    for i in 0..node.child_count() {
        if let Some(child) = node.child(i) {
            if child.kind() == "jsx_text" {
                let text = node_text(child, source);
                if !text.trim().is_empty() {
                    if !content.is_empty() {
                        content.push(' ');
                    }
                    content.push_str(text.trim());
                }
            }
        }
    }
    if content.is_empty() {
        None
    } else {
        Some(content)
    }
}

fn parse_proof_declaration(
    attrs: &BTreeMap<String, String>,
    source_span: SourceSpan,
) -> Option<PolyglotProofDeclaration> {
    let proof = attrs.get("data-proof")?;
    let mut split = proof.splitn(2, ':');
    let system = split.next()?.trim().to_string();
    let theorem = split.next()?.trim().to_string();
    if system.is_empty() || theorem.is_empty() {
        return None;
    }
    Some(PolyglotProofDeclaration {
        system,
        theorem,
        status: attrs.get("data-proof-status").cloned(),
        source: attrs.get("data-proof-source").cloned(),
        expression: attrs.get("data-proof-expr").cloned(),
        source_span: Some(source_span),
    })
}

fn extract_proof_declarations_from_source(
    source: &str,
    file_path: &str,
) -> Vec<PolyglotProofDeclaration> {
    let mut proofs = Vec::new();
    let tag_regex = regex::Regex::new(r#"<[^>]*data-proof\s*=\s*["']([^"']+)["'][^>]*>"#)
        .expect("proof regex must compile");
    let status_regex =
        regex::Regex::new(r#"data-proof-status\s*=\s*["']([^"']+)["']"#).expect("status regex");
    let source_regex =
        regex::Regex::new(r#"data-proof-source\s*=\s*["']([^"']+)["']"#).expect("source regex");
    let expr_regex =
        regex::Regex::new(r#"data-proof-expr\s*=\s*["']([^"']+)["']"#).expect("expr regex");

    for capture in tag_regex.captures_iter(source) {
        let Some(matched) = capture.get(0) else {
            continue;
        };
        let Some(proof_value) = capture.get(1) else {
            continue;
        };
        let raw = proof_value.as_str();
        let mut split = raw.splitn(2, ':');
        let Some(system) = split.next() else {
            continue;
        };
        let Some(theorem) = split.next() else {
            continue;
        };
        if system.trim().is_empty() || theorem.trim().is_empty() {
            continue;
        }
        let tag_text = matched.as_str();
        let status = status_regex
            .captures(tag_text)
            .and_then(|caps| caps.get(1).map(|value| value.as_str().to_string()));
        let source_path = source_regex
            .captures(tag_text)
            .and_then(|caps| caps.get(1).map(|value| value.as_str().to_string()));
        let expression = expr_regex
            .captures(tag_text)
            .and_then(|caps| caps.get(1).map(|value| value.as_str().to_string()));
        let prefix = &source[..matched.start()];
        let line = prefix.chars().filter(|c| *c == '\n').count() + 1;
        let col = prefix
            .rfind('\n')
            .map(|idx| prefix.len() - idx)
            .unwrap_or(prefix.len() + 1);
        proofs.push(PolyglotProofDeclaration {
            system: system.trim().to_string(),
            theorem: theorem.trim().to_string(),
            status,
            source: source_path,
            expression,
            source_span: Some(SourceSpan {
                file: file_path.to_string(),
                start_line: line,
                start_column: col,
                end_line: line,
                end_column: col + 1,
                start_byte: matched.start(),
                end_byte: matched.end(),
            }),
        });
    }

    proofs
}

// ─────────────────────────────────────────────────────────────────────────────
// Semantic expression IR for orchestration mode.
//
// Translates a tree-sitter TypeScript expression node into a small JSON IR
// that downstream walkers (notably gnexec) can evaluate without re-parsing the
// source via tree-sitter at execution time. This is intentionally narrow: the
// IR covers what echo.ts / fib.ts / fanout.ts actually use. Anything we do not
// recognize falls back to a `raw` literal carrying the verbatim source text,
// which keeps the GG round-trippable and lets the walker still execute via the
// byte-range fallback path.
// ─────────────────────────────────────────────────────────────────────────────

/// Build orchestration-only properties for a `return_statement` node.
/// Walks tree-sitter to find the returned expression, converts it to IR via
/// `ts_node_to_ir`, then delegates to the language-agnostic helper.
fn build_return_props(node: &Node, source: &str) -> BTreeMap<String, String> {
    let mut cursor = node.walk();
    let expr = node
        .named_children(&mut cursor)
        .find(|child| !is_type_or_comment(child));
    match expr {
        Some(expr_node) => {
            let ir = ts_node_to_ir(&expr_node, source);
            ir_build_return_props(ir)
        }
        None => BTreeMap::new(),
    }
}

/// Build orchestration-only properties for an `expression_statement` node.
/// Handles `x = expr;` assignments (TS-specific tree-sitter dispatch) and bare
/// expression statements (delegated to the shared helper).
fn build_expression_statement_props(node: &Node, source: &str) -> BTreeMap<String, String> {
    let mut cursor = node.walk();
    let inner = node
        .named_children(&mut cursor)
        .find(|child| !is_type_or_comment(child));
    let Some(inner) = inner else {
        return BTreeMap::new();
    };

    // Assignment shape `x = expr;` / `x.y = expr;` is TS-specific (tree-sitter
    // produces `assignment_expression`). Build the bind/expr/callee/args map
    // inline; we can't fully reuse `build_declaration_props` because TS
    // assignments allow `bind_target` (non-ident, non-pattern lvalues) which
    // declarations do not.
    if inner.kind() == "assignment_expression" {
        let mut props = BTreeMap::new();
        if let Some(left) = inner.child_by_field_name("left") {
            let bind_ir = ts_node_to_ir(&left, source);
            if let Some(name) = ir_as_simple_ident(&bind_ir) {
                props.insert("bind".to_string(), name);
            } else if let Ok(s) = serde_json::to_string(&bind_ir) {
                props.insert("bind_target".to_string(), s);
            }
        }
        if let Some(right) = inner.child_by_field_name("right") {
            let value_ir = ts_node_to_ir(&right, source);
            if let Ok(s) = serde_json::to_string(&value_ir) {
                props.insert("expr".to_string(), s);
            }
            if let Some((callee, args)) = ir_call_callee_args(&value_ir) {
                props.insert("callee".to_string(), callee);
                if let Ok(args_json) = serde_json::to_string(&args) {
                    props.insert("args".to_string(), args_json);
                }
            }
        }
        return props;
    }

    let ir = ts_node_to_ir(&inner, source);
    ir_build_expression_statement_props(ir, None, None)
}

/// Build orchestration-only properties for a `lexical_declaration` /
/// `variable_declaration` node. Captures the bound name(s) and the initializer
/// expression IR.
fn build_declaration_props(node: &Node, source: &str) -> BTreeMap<String, String> {
    let mut cursor = node.walk();
    let declarator = node
        .named_children(&mut cursor)
        .find(|child| child.kind() == "variable_declarator");
    let Some(declarator) = declarator else {
        return BTreeMap::new();
    };

    // Resolve the bind name (or a destructuring pattern). Destructuring goes
    // through `bind_pattern` rather than the shared `bind` slot, so we can't
    // use the shared `build_declaration_props` directly when the name is a
    // pattern — fall through to inline construction in that case.
    let bind_node = declarator.child_by_field_name("name");
    let bind_ir = bind_node.map(|n| ts_node_to_ir(&n, source));
    let value_ir = declarator
        .child_by_field_name("value")
        .map(|n| ts_node_to_ir(&n, source));

    match (bind_ir.as_ref().and_then(ir_as_simple_ident), value_ir) {
        (Some(simple), Some(v_ir)) => ir_build_declaration_props(&simple, v_ir),
        (Some(simple), None) => {
            let mut props = BTreeMap::new();
            props.insert("bind".to_string(), simple);
            props
        }
        (None, value_ir_opt) => {
            let mut props = BTreeMap::new();
            if let Some(b) = bind_ir {
                if let Ok(s) = serde_json::to_string(&b) {
                    // Destructuring patterns: emit structured form.
                    props.insert("bind_pattern".to_string(), s);
                }
            }
            if let Some(v_ir) = value_ir_opt {
                if let Ok(s) = serde_json::to_string(&v_ir) {
                    props.insert("expr".to_string(), s);
                }
                if let Some((callee, args)) = ir_call_callee_args(&v_ir) {
                    props.insert("callee".to_string(), callee);
                    if let Ok(args_json) = serde_json::to_string(&args) {
                        props.insert("args".to_string(), args_json);
                    }
                }
            }
            props
        }
    }
}

/// Collect module-level binding declarations (`const`/`let`/`var`, including
/// the `export const X = ...` form) and serialize them into a JSON array
/// suitable for the `module_preamble` Entry property.
///
/// Each emitted entry has the shape `{ "bind": "<name>", "expr": <ir> }` and
/// preserves source order so a later declaration that references an earlier
/// one (e.g. `const A = 1; const B = A + 1;`) evaluates in the right order.
///
/// Returns `None` when there are no liftable declarations so the property is
/// simply omitted (keeping Analysis-mode output unchanged for files without
/// module-scope state).
///
/// Currently supports identifier-only lvalues (`const X = ...`). Multi-
/// declarator forms (`const a = 1, b = 2;`), destructuring patterns, and
/// side-effecting top-level statements are deliberately skipped — see the
/// recon notes; the entry blockers are simple-identifier consts.
fn collect_module_preamble(root: &Node, source: &str) -> Option<String> {
    let mut decls: Vec<serde_json::Value> = Vec::new();
    let mut cursor = root.walk();
    for child in root.named_children(&mut cursor) {
        collect_preamble_from_top_level(&child, source, &mut decls);
    }
    if decls.is_empty() {
        return None;
    }
    serde_json::to_string(&decls).ok()
}

/// Walk one top-level node and append any liftable bindings to `decls`. Peels
/// `export_statement` wrappers so `export const NAME = ...` lifts the same as
/// the plain form. Type-only declarations (`type`, `interface`) are skipped
/// because they have no runtime effect; imports are handled by the multi-file
/// resolver and intentionally not lifted here.
fn collect_preamble_from_top_level(node: &Node, source: &str, decls: &mut Vec<serde_json::Value>) {
    match node.kind() {
        "lexical_declaration" | "variable_declaration" => {
            collect_preamble_from_declaration(node, source, decls);
        }
        "export_statement" => {
            // `export const NAME = ...;` — recurse into named children to find
            // the inner declaration. Skip `export { foo }` re-export forms by
            // only descending into actual declaration nodes.
            let mut cursor = node.walk();
            for child in node.named_children(&mut cursor) {
                match child.kind() {
                    "lexical_declaration" | "variable_declaration" => {
                        collect_preamble_from_declaration(&child, source, decls);
                    }
                    _ => {}
                }
            }
        }
        // Type-only forms and imports: skipped on purpose.
        _ => {}
    }
}

/// Convert each `variable_declarator` inside a `lexical_declaration` /
/// `variable_declaration` into a `{bind, expr}` JSON entry. Skips declarators
/// with non-identifier lvalues (destructuring) and declarators without an
/// initializer — both round-trip more cleanly when handled by the function
/// body or runtime defaults.
fn collect_preamble_from_declaration(
    node: &Node,
    source: &str,
    decls: &mut Vec<serde_json::Value>,
) {
    let mut cursor = node.walk();
    for child in node.named_children(&mut cursor) {
        if child.kind() != "variable_declarator" {
            continue;
        }
        let bind_node = match child.child_by_field_name("name") {
            Some(n) => n,
            None => continue,
        };
        // Identifier-only lvalues — see the recon-time scope note.
        if bind_node.kind() != "identifier" {
            continue;
        }
        let bind_name = node_text(bind_node, source);
        let value_node = match child.child_by_field_name("value") {
            Some(n) => n,
            None => continue,
        };
        let expr_ir = ts_node_to_ir(&value_node, source);
        decls.push(serde_json::json!({
            "bind": bind_name,
            "expr": expr_ir,
        }));
    }
}

/// Convert a tree-sitter expression node into the orchestration IR.
fn ts_node_to_ir(node: &Node, source: &str) -> serde_json::Value {
    use serde_json::{json, Number, Value};
    let kind = node.kind();
    match kind {
        // Literal scalars.
        "number" => {
            let raw = node_text(*node, source);
            // JS supports underscore separators (`100_000`), hex (`0xff`), octal
            // (`0o77`), and binary (`0b1010`) literals. Strip underscores; route
            // each radix prefix through i64::from_str_radix so the IR carries
            // a real Number, not the source-text string.
            let text = raw.replace('_', "");
            let lower = text.to_lowercase();
            let value = if let Some(hex) = lower.strip_prefix("0x") {
                i64::from_str_radix(hex, 16)
                    .map(|i| Value::Number(Number::from(i)))
                    .unwrap_or_else(|_| Value::String(raw.clone()))
            } else if let Some(oct) = lower.strip_prefix("0o") {
                i64::from_str_radix(oct, 8)
                    .map(|i| Value::Number(Number::from(i)))
                    .unwrap_or_else(|_| Value::String(raw.clone()))
            } else if let Some(bin) = lower.strip_prefix("0b") {
                i64::from_str_radix(bin, 2)
                    .map(|i| Value::Number(Number::from(i)))
                    .unwrap_or_else(|_| Value::String(raw.clone()))
            } else if let Some(stripped) = text.strip_suffix('n') {
                // BigInt literal; truncate to i64 for our purposes.
                stripped
                    .parse::<i64>()
                    .map(|i| Value::Number(Number::from(i)))
                    .unwrap_or_else(|_| Value::String(raw.clone()))
            } else if let Ok(i) = text.parse::<i64>() {
                Value::Number(Number::from(i))
            } else if let Ok(f) = text.parse::<f64>() {
                Number::from_f64(f)
                    .map(Value::Number)
                    .unwrap_or(Value::String(raw.clone()))
            } else {
                Value::String(raw)
            };
            json!({ "kind": "literal", "value": value })
        }
        "true" => json!({ "kind": "literal", "value": true }),
        "false" => json!({ "kind": "literal", "value": false }),
        "null" => json!({ "kind": "literal", "value": Value::Null }),
        // `undefined` is a JS global identifier, not a literal. Emitting as ident lets
        // the typeof IR walker's unbound-catch return "undefined" instead of collapsing
        // into `typeof null` (which yields "object"). Bug found 2026-04-25 in def-typeof.
        "undefined" => json!({ "kind": "ident", "name": "undefined" }),
        "string" => {
            let s = ts_string_literal_value(node, source);
            json!({ "kind": "literal", "value": s })
        }
        "regex" => json!({ "kind": "raw", "text": node_text(*node, source) }),
        "identifier" | "shorthand_property_identifier" | "property_identifier" => {
            json!({ "kind": "ident", "name": node_text(*node, source) })
        }
        "this" => json!({ "kind": "ident", "name": "this" }),
        "parenthesized_expression" => {
            let mut cursor = node.walk();
            for child in node.named_children(&mut cursor) {
                if !is_type_or_comment(&child) {
                    return ts_node_to_ir(&child, source);
                }
            }
            json!({ "kind": "raw", "text": node_text(*node, source) })
        }
        // Type-only wrappers: unwrap to the inner expression.
        "as_expression" | "satisfies_expression" | "type_assertion" | "non_null_expression" => {
            let mut cursor = node.walk();
            for child in node.named_children(&mut cursor) {
                if !is_type_or_comment(&child) && !is_type_node(&child) {
                    return ts_node_to_ir(&child, source);
                }
            }
            json!({ "kind": "raw", "text": node_text(*node, source) })
        }
        "member_expression" => {
            let obj = node
                .child_by_field_name("object")
                .map(|n| ts_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            let prop = node
                .child_by_field_name("property")
                .map(|n| node_text(n, source))
                .unwrap_or_default();
            json!({ "kind": "member", "obj": obj, "prop": prop })
        }
        "subscript_expression" => {
            let obj = node
                .child_by_field_name("object")
                .map(|n| ts_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            let key = node
                .child_by_field_name("index")
                .map(|n| ts_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            json!({ "kind": "index", "obj": obj, "key": key })
        }
        "call_expression" => {
            let func = node.child_by_field_name("function");
            let callee_value = match &func {
                Some(f) => {
                    let f_kind = f.kind();
                    if f_kind == "identifier" || f_kind == "property_identifier" {
                        Value::String(node_text(*f, source))
                    } else {
                        ts_node_to_ir(f, source)
                    }
                }
                None => Value::Null,
            };
            let mut args: Vec<Value> = Vec::new();
            if let Some(args_node) = node.child_by_field_name("arguments") {
                let mut cursor = args_node.walk();
                for child in args_node.named_children(&mut cursor) {
                    if is_type_or_comment(&child) || is_type_node(&child) {
                        continue;
                    }
                    if child.kind() == "spread_element" {
                        let mut inner_cursor = child.walk();
                        let inner = child
                            .named_children(&mut inner_cursor)
                            .find(|c| !is_type_or_comment(c));
                        let inner_ir = inner
                            .map(|n| ts_node_to_ir(&n, source))
                            .unwrap_or(Value::Null);
                        args.push(json!({ "kind": "spread", "arg": inner_ir }));
                    } else {
                        args.push(ts_node_to_ir(&child, source));
                    }
                }
            }
            json!({ "kind": "call", "callee": callee_value, "args": args })
        }
        "binary_expression" => {
            let lhs = node
                .child_by_field_name("left")
                .map(|n| ts_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            let rhs = node
                .child_by_field_name("right")
                .map(|n| ts_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            let op = node
                .child_by_field_name("operator")
                .map(|n| node_text(n, source))
                .unwrap_or_default();
            json!({ "kind": "binary", "op": op, "lhs": lhs, "rhs": rhs })
        }
        "unary_expression" => {
            let arg = node
                .child_by_field_name("argument")
                .map(|n| ts_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            let op = node
                .child_by_field_name("operator")
                .map(|n| node_text(n, source))
                .unwrap_or_default();
            json!({ "kind": "unary", "op": op, "arg": arg })
        }
        "update_expression" => {
            let arg = node
                .child_by_field_name("argument")
                .map(|n| ts_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            let op = node
                .child_by_field_name("operator")
                .map(|n| node_text(n, source))
                .unwrap_or_default();
            json!({ "kind": "unary", "op": op, "arg": arg })
        }
        "ternary_expression" => {
            let cond = node
                .child_by_field_name("condition")
                .map(|n| ts_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            let cons = node
                .child_by_field_name("consequence")
                .map(|n| ts_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            let alt = node
                .child_by_field_name("alternative")
                .map(|n| ts_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            json!({ "kind": "ternary", "cond": cond, "cons": cons, "alt": alt })
        }
        "template_string" => {
            let mut parts: Vec<Value> = Vec::new();
            let mut cursor = node.walk();
            for child in node.named_children(&mut cursor) {
                match child.kind() {
                    "string_fragment" | "escape_sequence" => {
                        parts.push(json!({ "kind": "text", "s": decode_js_escapes(&node_text(child, source)) }));
                    }
                    "template_substitution" => {
                        let mut sub_cursor = child.walk();
                        let inner = child
                            .named_children(&mut sub_cursor)
                            .find(|c| !is_type_or_comment(c));
                        let inner_ir = inner
                            .map(|n| ts_node_to_ir(&n, source))
                            .unwrap_or(Value::Null);
                        parts.push(json!({ "kind": "expr", "e": inner_ir }));
                    }
                    _ => {}
                }
            }
            json!({ "kind": "template", "parts": parts })
        }
        "array" => {
            let mut items: Vec<Value> = Vec::new();
            let mut cursor = node.walk();
            for child in node.named_children(&mut cursor) {
                if is_type_or_comment(&child) {
                    continue;
                }
                if child.kind() == "spread_element" {
                    let mut inner_cursor = child.walk();
                    let inner = child
                        .named_children(&mut inner_cursor)
                        .find(|c| !is_type_or_comment(c));
                    let inner_ir = inner
                        .map(|n| ts_node_to_ir(&n, source))
                        .unwrap_or(Value::Null);
                    items.push(json!({ "kind": "spread", "arg": inner_ir }));
                } else {
                    items.push(ts_node_to_ir(&child, source));
                }
            }
            json!({ "kind": "array", "items": items })
        }
        "object" => {
            let mut fields: Vec<Value> = Vec::new();
            let mut cursor = node.walk();
            for child in node.named_children(&mut cursor) {
                match child.kind() {
                    "pair" => {
                        let key_text = child
                            .child_by_field_name("key")
                            .map(|n| {
                                if n.kind() == "string" {
                                    ts_string_literal_value(&n, source)
                                } else {
                                    node_text(n, source)
                                }
                            })
                            .unwrap_or_default();
                        let value_ir = child
                            .child_by_field_name("value")
                            .map(|n| ts_node_to_ir(&n, source))
                            .unwrap_or(Value::Null);
                        fields.push(json!({ "k": key_text, "v": value_ir }));
                    }
                    "shorthand_property_identifier" | "shorthand_property_identifier_pattern" => {
                        let name = node_text(child, source);
                        fields.push(json!({
                            "k": name,
                            "v": { "kind": "ident", "name": name }
                        }));
                    }
                    "spread_element" => {
                        let mut inner_cursor = child.walk();
                        let inner = child
                            .named_children(&mut inner_cursor)
                            .find(|c| !is_type_or_comment(c));
                        let inner_ir = inner
                            .map(|n| ts_node_to_ir(&n, source))
                            .unwrap_or(Value::Null);
                        fields.push(json!({ "k": "...", "v": inner_ir }));
                    }
                    _ => {}
                }
            }
            json!({ "kind": "object", "fields": fields })
        }
        // Destructuring patterns (used as bind targets).
        "array_pattern" => {
            let mut items: Vec<Value> = Vec::new();
            let mut cursor = node.walk();
            for child in node.named_children(&mut cursor) {
                if is_type_or_comment(&child) {
                    continue;
                }
                items.push(ts_node_to_ir(&child, source));
            }
            json!({ "kind": "array_pattern", "items": items })
        }
        "object_pattern" => {
            let mut fields: Vec<Value> = Vec::new();
            let mut cursor = node.walk();
            for child in node.named_children(&mut cursor) {
                if is_type_or_comment(&child) {
                    continue;
                }
                match child.kind() {
                    "shorthand_property_identifier_pattern" | "shorthand_property_identifier" => {
                        fields.push(json!({ "k": node_text(child, source) }));
                    }
                    "pair_pattern" => {
                        let key_text = child
                            .child_by_field_name("key")
                            .map(|n| node_text(n, source))
                            .unwrap_or_default();
                        let value_ir = child
                            .child_by_field_name("value")
                            .map(|n| ts_node_to_ir(&n, source))
                            .unwrap_or(Value::Null);
                        fields.push(json!({ "k": key_text, "v": value_ir }));
                    }
                    // `{ a = 99 }` — shorthand-with-default. tree-sitter wraps the
                    // ident in an `object_assignment_pattern` whose `left` is the
                    // shorthand ident and `right` is the default expression.
                    "object_assignment_pattern" => {
                        let key_text = child
                            .child_by_field_name("left")
                            .map(|n| node_text(n, source))
                            .unwrap_or_default();
                        let default_ir = child
                            .child_by_field_name("right")
                            .map(|n| ts_node_to_ir(&n, source))
                            .unwrap_or(Value::Null);
                        fields.push(json!({ "k": key_text, "default": default_ir }));
                    }
                    // `{ ...rest }` — rest pattern. Bind everything not matched
                    // above into a single named property.
                    "rest_pattern" => {
                        let inner = child
                            .named_child(0)
                            .map(|n| node_text(n, source))
                            .unwrap_or_default();
                        fields.push(json!({ "k": inner, "rest": true }));
                    }
                    _ => {}
                }
            }
            json!({ "kind": "object_pattern", "fields": fields })
        }
        "await_expression" => {
            let mut cursor = node.walk();
            let inner = node
                .named_children(&mut cursor)
                .find(|c| !is_type_or_comment(c));
            let inner_ir = inner
                .map(|n| ts_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            json!({ "kind": "await", "arg": inner_ir })
        }
        "yield_expression" => {
            let mut cursor = node.walk();
            let inner = node
                .named_children(&mut cursor)
                .find(|c| !is_type_or_comment(c));
            let inner_ir = inner
                .map(|n| ts_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            json!({ "kind": "yield", "arg": inner_ir })
        }
        // Constructor call: `new Map<K,V>(...)`. Mirror call_expression but
        // emit `kind:"new"` so gnexec dispatch can construct (vs invoke).
        // Drops `type_arguments` (TS-only).
        "new_expression" => {
            let cons_ir = node
                .child_by_field_name("constructor")
                .map(|n| ts_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            let mut args: Vec<Value> = Vec::new();
            if let Some(args_node) = node.child_by_field_name("arguments") {
                let mut cursor = args_node.walk();
                for child in args_node.named_children(&mut cursor) {
                    if is_type_or_comment(&child) || is_type_node(&child) {
                        continue;
                    }
                    if child.kind() == "spread_element" {
                        let mut inner_cursor = child.walk();
                        let inner = child
                            .named_children(&mut inner_cursor)
                            .find(|c| !is_type_or_comment(c));
                        let inner_ir = inner
                            .map(|n| ts_node_to_ir(&n, source))
                            .unwrap_or(Value::Null);
                        args.push(json!({ "kind": "spread", "arg": inner_ir }));
                    } else {
                        args.push(ts_node_to_ir(&child, source));
                    }
                }
            }
            json!({ "kind": "new", "callee": cons_ir, "args": args })
        }
        // Arrow function expression. Lowered structurally so gnexec can
        // construct a callable without re-parsing the source string. Body is
        // carried as raw source text — a future gnexec arm will swap in a
        // synthetic source / re-parse to evaluate the body, mirroring the
        // existing `raw_arrow` path (see `invoke_callable_inner`). Two arrow
        // shapes:
        //   `(a, b) => …`  — `parameters` field, list of formal_parameter
        //   `v => …`       — `parameter` field, bare identifier
        "arrow_function" => {
            let mut params: Vec<Value> = Vec::new();
            if let Some(pn) = node.child_by_field_name("parameters") {
                let mut walker = pn.walk();
                for c in pn.named_children(&mut walker) {
                    let id_node = match c.kind() {
                        "required_parameter" | "optional_parameter" => {
                            c.child_by_field_name("pattern").unwrap_or(c)
                        }
                        _ => c,
                    };
                    if id_node.kind() == "identifier" {
                        params.push(Value::String(node_text(id_node, source)));
                    }
                }
            } else if let Some(p) = node.child_by_field_name("parameter") {
                if p.kind() == "identifier" {
                    params.push(Value::String(node_text(p, source)));
                }
            }
            let body_text = node
                .child_by_field_name("body")
                .map(|n| node_text(n, source))
                .unwrap_or_default();
            // `async ` prefix lives on the arrow_function node text.
            let is_async = node_text(*node, source).trim_start().starts_with("async");
            json!({
                "kind": "lambda",
                "params": params,
                "body_text": body_text,
                "async": is_async,
            })
        }
        // Compound assignment: `x += 1`, `vec[i] /= magnitude`. Lowered to a
        // structural assign so gnexec can route through its bind/index/member
        // dispatch. Pure `=` arrives as `assignment_expression` and is handled
        // in `build_expression_statement_props` already.
        "augmented_assignment_expression" => {
            let target = node
                .child_by_field_name("left")
                .map(|n| ts_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            let value = node
                .child_by_field_name("right")
                .map(|n| ts_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            let op = node
                .child_by_field_name("operator")
                .map(|n| node_text(n, source))
                .unwrap_or_default();
            json!({ "kind": "assign", "target": target, "op": op, "value": value })
        }
        "jsx_element" => {
            let mut cursor = node.walk();
            let opening = node
                .named_children(&mut cursor)
                .find(|c| c.kind() == "jsx_opening_element");
            let tag = opening
                .as_ref()
                .and_then(|o| o.child_by_field_name("name"))
                .map(|n| ts_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            let attrs = opening
                .as_ref()
                .map(|o| jsx_attrs_to_ir(o, source))
                .unwrap_or_default();
            let children = jsx_children_to_ir(node, source);
            json!({ "kind": "jsx_element", "tag": tag, "attrs": attrs, "children": children })
        }
        "jsx_self_closing_element" => {
            let tag = node
                .child_by_field_name("name")
                .map(|n| ts_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            let attrs = jsx_attrs_to_ir(node, source);
            json!({ "kind": "jsx_self_closing", "tag": tag, "attrs": attrs })
        }
        "jsx_text" => {
            json!({ "kind": "jsx_text", "value": node_text(*node, source).trim().to_string() })
        }
        "jsx_expression" => {
            // tree-sitter-typescript names this `jsx_expression`; some
            // grammars use `jsx_expression_container`. Both wrap a single
            // named child expression in `{ ... }`.
            let mut cursor = node.walk();
            let inner = node
                .named_children(&mut cursor)
                .find(|c| c.kind() != "comment")
                .map(|c| ts_node_to_ir(&c, source))
                .unwrap_or(Value::Null);
            json!({ "kind": "jsx_expr", "expr": inner })
        }
        "jsx_fragment" => {
            let children = jsx_children_to_ir(node, source);
            json!({ "kind": "jsx_fragment", "children": children })
        }
        // Anything else: emit a raw escape hatch so the GG remains complete.
        _ => json!({ "kind": "raw", "text": node_text(*node, source) }),
    }
}

/// Lower JSX attributes (children of a `jsx_opening_element` /
/// `jsx_self_closing_element`) into a list of `{name, value}` pairs.
/// Spread attributes (`{...rest}`) emit `{name:"...", value:{kind:"spread",arg}}`
/// using the same convention as call/array spread.
fn jsx_attrs_to_ir(opening: &Node, source: &str) -> Vec<serde_json::Value> {
    use serde_json::{json, Value};
    let mut out: Vec<Value> = Vec::new();
    let mut cursor = opening.walk();
    for child in opening.named_children(&mut cursor) {
        match child.kind() {
            "jsx_attribute" => {
                let name = child
                    .named_child(0)
                    .map(|n| node_text(n, source))
                    .unwrap_or_default();
                // The value is everything after the name. Could be string,
                // jsx_expression, or absent (boolean attribute).
                let value = if child.named_child_count() > 1 {
                    child
                        .named_child(1)
                        .map(|v| ts_node_to_ir(&v, source))
                        .unwrap_or(Value::Bool(true))
                } else {
                    Value::Bool(true)
                };
                out.push(json!({ "name": name, "value": value }));
            }
            "jsx_spread_attribute" | "jsx_spread_child" => {
                // {...rest} inside the opening element.
                let inner = child
                    .named_child(0)
                    .map(|n| ts_node_to_ir(&n, source))
                    .unwrap_or(Value::Null);
                out.push(json!({
                    "name": "...",
                    "value": { "kind": "spread", "arg": inner }
                }));
            }
            _ => {}
        }
    }
    out
}

/// Lower JSX element / fragment children, skipping the opening / closing
/// element wrappers that tree-sitter emits as named children.
fn jsx_children_to_ir(node: &Node, source: &str) -> Vec<serde_json::Value> {
    let mut out: Vec<serde_json::Value> = Vec::new();
    let mut cursor = node.walk();
    for child in node.named_children(&mut cursor) {
        match child.kind() {
            "jsx_opening_element" | "jsx_closing_element" | "comment" => continue,
            _ => {}
        }
        out.push(ts_node_to_ir(&child, source));
    }
    out
}

/// Strip surrounding quotes from a `string` node and concatenate its fragments.
/// Decode a JS/TS string's source text (a `string_fragment` or an
/// `escape_sequence` token) into the characters it denotes: `\n`→newline,
/// `\t`→tab, `\\`→backslash, `\xHH`, `\uHHHH`, `\u{…}`, etc. Non-escape text is
/// passed through unchanged. The IR `literal` value is baked at extraction time
/// (gnexec's `eval_ir` reads it verbatim), so escapes MUST be decoded here — a
/// raw `\n` in the IR would otherwise leave a literal backslash-n that breaks
/// any code matching on a real newline (e.g. the MCP bridge's framing
/// `input.indexOf('\n')`).
pub(crate) fn decode_js_escapes(s: &str) -> String {
    let mut out = String::with_capacity(s.len());
    let mut chars = s.chars().peekable();
    while let Some(c) = chars.next() {
        if c != '\\' {
            out.push(c);
            continue;
        }
        match chars.next() {
            Some('n') => out.push('\n'),
            Some('t') => out.push('\t'),
            Some('r') => out.push('\r'),
            Some('b') => out.push('\u{0008}'),
            Some('f') => out.push('\u{000C}'),
            Some('v') => out.push('\u{000B}'),
            Some('0') => out.push('\0'),
            Some('\\') => out.push('\\'),
            Some('\'') => out.push('\''),
            Some('"') => out.push('"'),
            Some('`') => out.push('`'),
            Some('$') => out.push('$'),
            Some('\n') => {} // line continuation: backslash-newline → nothing
            Some('x') => {
                let hex: String = (0..2).filter_map(|_| chars.next()).collect();
                if let Ok(code) = u32::from_str_radix(&hex, 16) {
                    if let Some(ch) = char::from_u32(code) {
                        out.push(ch);
                    }
                }
            }
            Some('u') => {
                if chars.peek() == Some(&'{') {
                    chars.next();
                    let mut hex = String::new();
                    for d in chars.by_ref() {
                        if d == '}' {
                            break;
                        }
                        hex.push(d);
                    }
                    if let Ok(code) = u32::from_str_radix(&hex, 16) {
                        if let Some(ch) = char::from_u32(code) {
                            out.push(ch);
                        }
                    }
                } else {
                    let hex: String = (0..4).filter_map(|_| chars.next()).collect();
                    if let Ok(code) = u32::from_str_radix(&hex, 16) {
                        if let Some(ch) = char::from_u32(code) {
                            out.push(ch);
                        }
                    }
                }
            }
            Some(other) => out.push(other), // unknown escape: drop the backslash
            None => out.push('\\'),
        }
    }
    out
}

fn ts_string_literal_value(node: &Node, source: &str) -> String {
    let mut out = String::new();
    let mut cursor = node.walk();
    for child in node.named_children(&mut cursor) {
        if child.kind() == "string_fragment" || child.kind() == "escape_sequence" {
            out.push_str(&decode_js_escapes(&node_text(child, source)));
        }
    }
    if out.is_empty() {
        let raw = node_text(*node, source);
        let trimmed = raw.trim();
        if trimmed.len() >= 2 {
            let bytes = trimmed.as_bytes();
            let q = bytes[0];
            if (q == b'"' || q == b'\'' || q == b'`') && bytes[bytes.len() - 1] == q {
                return decode_js_escapes(&trimmed[1..trimmed.len() - 1]);
            }
        }
        return raw;
    }
    out
}

/// True if `node` is a comment or type annotation we want to skip.
fn is_type_or_comment(node: &Node) -> bool {
    matches!(node.kind(), "comment" | "type_annotation")
}

/// True if `node` is purely a type-syntax wrapper that should be unwrapped.
fn is_type_node(node: &Node) -> bool {
    matches!(
        node.kind(),
        "type_annotation"
            | "type_arguments"
            | "type_parameters"
            | "predefined_type"
            | "type_identifier"
            | "generic_type"
    )
}

/// Build a Statement node that runs `this.<field> = <value_ir>` and append it
/// to the given CFG, chained from the current `last` node. Returns the new
/// last node id.
fn append_field_init_stmt(
    cfg: &mut ControlFlowGraph,
    field_name: &str,
    value_node: &Node,
    source: &str,
    file_path: &str,
    last: usize,
) -> usize {
    let value_ir = ts_node_to_ir(value_node, source);
    let mut props = BTreeMap::new();
    let target_ir = serde_json::json!({
        "kind": "member",
        "obj": {"kind": "ident", "name": "this"},
        "prop": field_name,
    });
    if let Ok(s) = serde_json::to_string(&target_ir) {
        props.insert("bind_target".to_string(), s);
    }
    if let Ok(s) = serde_json::to_string(&value_ir) {
        props.insert("expr".to_string(), s);
    }
    let stmt = cfg.add_node_with_props(
        CfgNodeKind::Statement,
        SourceSpan::from_tree_sitter(file_path, value_node),
        format!("this.{} = …", field_name),
        props,
    );
    cfg.add_edge(last, stmt, None);
    stmt
}

/// Inject field initializers at the start of an explicit constructor's CFG.
/// We rewire so that the entry's existing PROCESS edges go through the field
/// inits first, then on into the original first body node.
fn inject_field_inits_into_cfg(
    cfg: &mut ControlFlowGraph,
    fields: &[(String, Node, String)],
    source: &str,
    file_path: &str,
) {
    if fields.is_empty() {
        return;
    }
    let entry_id = cfg.entry;
    // Capture the original successors of entry and detach them.
    let original_targets: Vec<usize> = cfg
        .edges
        .iter()
        .filter(|e| e.from == entry_id)
        .map(|e| e.to)
        .collect();
    cfg.edges.retain(|e| e.from != entry_id);

    // Chain field-init statements from the entry.
    let mut last = entry_id;
    for (fname, vnode, _vtext) in fields {
        last = append_field_init_stmt(cfg, fname, vnode, source, file_path, last);
    }
    // Reconnect the chain head to the original successors.
    for tgt in original_targets {
        cfg.add_edge(last, tgt, None);
    }
}

/// Synthesize a `<Class>.constructor` topology that runs only the field
/// initializers. Used when the class has fields but no explicit constructor.
fn synthesize_field_init_constructor(
    qualified: &str,
    class_name: &str,
    fields: &[(String, Node, String)],
    source: &str,
    file_path: &str,
) -> Result<ControlFlowGraph> {
    let mut cfg = ControlFlowGraph::new(
        qualified.to_string(),
        "typescript".to_string(),
        file_path.to_string(),
    );
    let entry_props = ir_build_entry_props(&[]);
    let entry = cfg.add_node_with_props(
        CfgNodeKind::Entry {
            name: qualified.to_string(),
        },
        SourceSpan {
            file: file_path.to_string(),
            start_line: 1,
            start_column: 1,
            end_line: 1,
            end_column: 1,
            start_byte: 0,
            end_byte: 0,
        },
        format!("synthesized constructor for {}", class_name),
        entry_props,
    );
    cfg.entry = entry;
    if let Some(node) = cfg.nodes.get_mut(entry) {
        node.extra_properties
            .insert("class_name".to_string(), class_name.to_string());
        node.extra_properties
            .insert("method_name".to_string(), "constructor".to_string());
        node.extra_properties
            .insert("synthetic".to_string(), "field_init".to_string());
    }
    let mut last = entry;
    for (fname, vnode, _vtext) in fields {
        last = append_field_init_stmt(&mut cfg, fname, vnode, source, file_path, last);
    }
    // Synthetic Return with an explicit `expr=literal:null` IR. Without this,
    // gnexec's byte-range fallback on a 0..0 source range climbs up to the
    // class node and surfaces 'unhandled AST node "class"'.
    let mut ret_props = BTreeMap::new();
    let null_ir = serde_json::json!({"kind": "literal", "value": null});
    if let Ok(s) = serde_json::to_string(&null_ir) {
        ret_props.insert("expr".to_string(), s);
    }
    let ret = cfg.add_node_with_props(
        CfgNodeKind::Return,
        SourceSpan {
            file: file_path.to_string(),
            start_line: 1,
            start_column: 1,
            end_line: 1,
            end_column: 1,
            start_byte: 0,
            end_byte: 0,
        },
        "implicit return".to_string(),
        ret_props,
    );
    cfg.add_edge(last, ret, None);
    cfg.exits.push(ret);
    Ok(cfg)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn extracts_simple_function() {
        let source = r#"
function greet(name: string): string {
    if (name === "world") {
        return "Hello, World!";
    } else {
        return `Hello, ${name}!`;
    }
}
"#;

        let extractor = TypeScriptExtractor;
        let cfgs = extractor.extract(source, "test.ts").unwrap();
        assert_eq!(cfgs.len(), 1);
        assert_eq!(cfgs[0].function_name, "greet");
        assert!(
            cfgs[0].nodes.len() >= 4,
            "should have entry, branch, then, else"
        );
    }

    #[test]
    fn detects_try_catch() {
        let source = r#"
function riskyOp() {
    try {
        dangerousCall();
    } catch (e) {
        handleError(e);
    }
}
"#;

        let extractor = TypeScriptExtractor;
        let cfgs = extractor.extract(source, "test.ts").unwrap();
        assert_eq!(cfgs.len(), 1);

        let has_try = cfgs[0]
            .nodes
            .iter()
            .any(|n| matches!(n.kind, CfgNodeKind::TryEntry));
        assert!(has_try, "should detect try entry");

        let has_catch = cfgs[0]
            .nodes
            .iter()
            .any(|n| matches!(n.kind, CfgNodeKind::CatchHandler));
        assert!(has_catch, "should detect catch handler");
    }

    #[test]
    fn detects_resource_acquire() {
        let source = r#"
function readFile() {
    const stream = fs.createReadStream("data.txt");
    const data = stream.read();
    stream.close();
    return data;
}
"#;

        let extractor = TypeScriptExtractor;
        let cfgs = extractor.extract(source, "test.ts").unwrap();
        assert_eq!(cfgs.len(), 1);

        let has_acquire = cfgs[0]
            .nodes
            .iter()
            .any(|n| matches!(n.kind, CfgNodeKind::ResourceAcquire { .. }));
        assert!(has_acquire, "should detect resource acquire");

        let has_release = cfgs[0]
            .nodes
            .iter()
            .any(|n| matches!(n.kind, CfgNodeKind::ResourceRelease { .. }));
        assert!(has_release, "should detect resource release");
    }

    #[test]
    fn extracts_jsx_structured_and_proof_declarations() {
        let source = r##"
const page = () => (
  <section data-sd-context='{"schema":"https://schema.org/","foaf":"http://xmlns.com/foaf/0.1/"}'>
    <article
      data-sd-id="#faq"
      data-sd-type="schema:FAQPage"
      data-proof="lean4:buleyean_positivity"
      data-proof-status="verified"
    />
    <div data-sd-id="#q1" data-sd-type="schema:Question" data-sd-prop="schema:name" data-sd-value="What is this?" />
    <div data-proof="aeon-logic:route_soundness" data-proof-expr="forall x. P(x) -> Q(x)" />
  </section>
);
"##;

        let extractor = TypeScriptExtractor;
        let artifacts = extractor
            .extract_with_artifacts(source, "page.tsx")
            .unwrap();
        assert!(artifacts.structured_declarations.len() >= 2);
        assert_eq!(artifacts.proof_declarations.len(), 2);
        assert!(artifacts
            .structured_declarations
            .iter()
            .any(|decl| decl.sd_id.as_deref() == Some("#faq")));
        assert!(artifacts
            .proof_declarations
            .iter()
            .any(|proof| proof.system == "aeon-logic"));
    }
}

// (Build-unblocker stubs that previously lived here have been replaced by the
// real `build_return_props` / `build_expression_statement_props` /
// `build_declaration_props` implementations defined above, which emit the
// structured `bind` / `args` / `expr` semantic IR for orchestration mode.)
